uint32_t Assets::CalculateChecksum(const char* data, uint32_t length)
{
    uint32_t checksum = 0;

    // Sum all byte values in the data buffer
    for (uint32_t i = 0; i < length; i++)
    {
        checksum += (uint8_t)data[i];
    }

    // Mask to 16 bits (keep only lower 16 bits)
    checksum &= 0xFFFF;

    return checksum;
}

