bool Assets::InitializePartition()
{
    ESP_LOGD(TAG, "Initializing assets partition");

    // Find the assets partition
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, 
        ESP_PARTITION_SUBTYPE_DATA_SPIFFS, 
        "assets"
    );

    if (!partition) {
        ESP_LOGE(TAG, "Failed to find assets partition");
        return false;
    }

    // Store partition reference
    partition_ = partition;

    // Map the partition into memory
    esp_err_t err = esp_partition_mmap(
        partition,
        0,
        partition->size,
        ESP_PARTITION_MMAP_DATA,
        (const void**)&mmap_root_,
        &mmap_handle_
    );

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_str(err));
        return false;
    }

    // Verify partition is valid (check for magic number or header)
    // Assuming first 4 bytes contain a magic number or version
    if (!mmap_root_) {
        ESP_LOGE(TAG, "Failed to get mapped memory address");
        return false;
    }

    // Basic validation - check if we have enough data for header
    if (partition->size < sizeof(mmap_assets_table)) {
        ESP_LOGE(TAG, "Partition too small for asset table");
        return false;
    }

    // Check if we can read the asset index (first entry)
    const mmap_assets_table* asset_table = reinterpret_cast<const mmap_assets_table*>(mmap_root_);

    // Validate the first entry's name is not empty (basic sanity check)
    if (asset_table->asset_name[0] == '\0') {
        ESP_LOGW(TAG, "No assets found in partition");
        partition_valid_ = true;  // Still consider this valid but empty
        checksum_valid_ = true;
        return true;
    }

    // Calculate and verify checksum of the entire partition
    uint32_t calculated_checksum = CalculateChecksum(mmap_root_, partition->size);

    // Assuming checksum is stored at the end of the partition
    // This is a common pattern - last 4 bytes might contain the checksum
    if (partition->size >= 4) {
        uint32_t stored_checksum = *reinterpret_cast<const uint32_t*>(mmap_root_ + partition->size - 4);

        if (calculated_checksum == stored_checksum) {
            checksum_valid_ = true;
        } else {
            ESP_LOGE(TAG, "Checksum mismatch: expected 0x%08X, got 0x%08X", 
                     calculated_checksum, stored_checksum);
            checksum_valid_ = false;
            return false;
        }
    } else {
        ESP_LOGW(TAG, "Partition too small for checksum validation");
        checksum_valid_ = false;
    }

    // Mark partition as valid
    partition_valid_ = true;

    ESP_LOGD(TAG, "Assets partition initialized successfully");
    return true;
}

