bool Assets::Apply()
{
    ESP_LOGI(TAG, "Applying assets...");

    // Load index.json file
    void* ptr = nullptr;
    size_t size = 0;

    if (!GetAssetData("index.json", ptr, size)) {
        ESP_LOGE(TAG, "Failed to load index.json");
        return false;
    }

    // Parse JSON configuration
    cJSON* json = cJSON_Parse((const char*)ptr);
    if (json == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json");
        return false;
    }

    // Validate asset version
    cJSON* version = cJSON_GetObjectItem(json, "version");
    if (version == nullptr || cJSON_IsString(version) == false) {
        ESP_LOGE(TAG, "Invalid or missing version in index.json");
        cJSON_Delete(json);
        return false;
    }

    // Check if this is a supported version
    const char* asset_version = cJSON_GetStringValue(version);
    if (strcmp(asset_version, "1.0") != 0) {  // Assuming version 1.0 is supported
        ESP_LOGW(TAG, "Unsupported asset version: %s", asset_version);
        // Continue processing but warn user
    }

    // Process assets section
    cJSON* assets = cJSON_GetObjectItem(json, "assets");
    if (assets != nullptr && cJSON_IsArray(assets)) {
        int asset_count = cJSON_GetArraySize(assets);
        for (int i = 0; i < asset_count; i++) {
            cJSON* asset_item = cJSON_GetArrayItem(assets, i);
            if (asset_item == nullptr) continue;

            cJSON* asset_name = cJSON_GetObjectItem(asset_item, "name");
            cJSON* asset_type = cJSON_GetObjectItem(asset_item, "type");
            cJSON* asset_path = cJSON_GetObjectItem(asset_item, "path");

            if (asset_name == nullptr || asset_type == nullptr || asset_path == nullptr) {
                continue;
            }

            const char* name = cJSON_GetStringValue(asset_name);
            const char* type = cJSON_GetStringValue(asset_type);
            const char* path = cJSON_GetStringValue(asset_path);

            if (name == nullptr || type == nullptr || path == nullptr) {
                continue;
            }

            // Handle different asset types
            if (strcmp(type, "theme") == 0) {
                // Apply UI theme
                ESP_LOGI(TAG, "Applying theme: %s", name);
                // TODO: Implement theme loading logic
            } else if (strcmp(type, "font") == 0) {
                // Load font
                ESP_LOGI(TAG, "Loading font: %s", name);
                // TODO: Implement font loading logic using cbin_font.h
            } else if (strcmp(type, "emoji") == 0) {
                // Load emoji set
                ESP_LOGI(TAG, "Loading emoji set: %s", name);
                // TODO: Implement emoji loading logic
            } else if (strcmp(type, "model") == 0) {
                // Load speech recognition model
                ESP_LOGI(TAG, "Loading model: %s", name);
                // TODO: Implement model loading logic
            } else {
                ESP_LOGW(TAG, "Unknown asset type: %s", type);
            }
        }
    }

    // Process models section if exists
    cJSON* models = cJSON_GetObjectItem(json, "models");
    if (models != nullptr && cJSON_IsArray(models)) {
        int model_count = cJSON_GetArraySize(models);
        for (int i = 0; i < model_count; i++) {
            cJSON* model_item = cJSON_GetArrayItem(models, i);
            if (model_item == nullptr) continue;

            cJSON* model_name = cJSON_GetObjectItem(model_item, "name");
            cJSON* model_path = cJSON_GetObjectItem(model_item, "path");

            if (model_name == nullptr || model_path == nullptr) {
                continue;
            }

            const char* name = cJSON_GetStringValue(model_name);
            const char* path = cJSON_GetStringValue(model_path);

            if (name == nullptr || path == nullptr) {
                continue;
            }

            ESP_LOGI(TAG, "Processing model: %s", name);
            // TODO: Add model processing logic here
        }
    }

    // Clean up
    cJSON_Delete(json);

    // Update checksum validation status
    checksum_valid_ = true;

    ESP_LOGI(TAG, "Assets applied successfully");
    return true;
}

