    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    // Get content length
    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Get content length
    size_t content_length = esp_http_client_get_content_length(client);
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Invalid content length");
        esp_http_client_cleanup(client);
        return false;
    }

    // Check if we have enough space in partition
    if (content_length > partition_->size) {
        ESP_LOGE(TAG, "Content size (%zu) exceeds partition size (%u)", content_length, partition_->size);
        esp_http_client_cleanup(client);
        return false;
    }

    // Erase the partition
    ESP_LOGI(TAG, "Erasing partition...");
    err = esp_partition_erase_range(partition_, 0, partition_->size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase partition: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Allocate buffer for reading data
    const size_t buffer_size = 4096;
    uint8_t* buffer = new uint8_t[buffer_size];
    if (!buffer) {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        esp_http_client_cleanup(client);
        return false;
    }

    // Start downloading and writing
    size_t total_written = 0;
    int last_progress = -1;
    uint64_t start_time = esp_timer_get_time();

    try {
        while (total_written < content_length) {
            size_t to_read = buffer_size;
            if (total_written + to_read > content_length) {
                to_read = content_length - total_written;
            }

            int bytes_read = esp_http_client_read(client, reinterpret_cast<char*>(buffer), to_read);
            if (bytes_read < 0) {
                ESP_LOGE(TAG, "Failed to read from HTTP client: %d", bytes_read);
                throw std::runtime_error("HTTP read failed");
            }

            if (bytes_read == 0) {
                break; // End of stream
            }

            // Write to flash partition
            err = esp_partition_write(partition_, total_written, buffer, bytes_read);
            if (err != ESP_OK) {
                ESP_LOGE(TAG, "Failed to write to partition: %s", esp_err_to_name(err));
                throw std::runtime_error("Flash write failed");
            }

            total_written += bytes_read;

            // Update progress
            int current_progress = (int)((total_written * 100) / content_length);
            if (current_progress != last_progress) {
                last_progress = current_progress;

                // Calculate speed
                uint64_t elapsed_us = esp_timer_get_time() - start_time;
                size_t speed = 0;
                if (elapsed_us > 0) {
                    speed = (total_written * 1000000ULL) / elapsed_us; // bytes per second
                }

                if (progress_callback) {
                    progress_callback(current_progress, speed);
                }
            }
        }

        delete[] buffer;
        esp_http_client_cleanup(client);

        // Verify download was complete
        if (total_written != content_length) {
            ESP_LOGE(TAG, "Download incomplete: expected %zu bytes, got %zu", content_length, total_written);
            return false;
        }

        ESP_LOGI(TAG, "Download completed successfully");
        return true;

    } catch (const std::exception& e) {
        ESP_LOGE(TAG, "Download error: %s", e.what());
        delete[] buffer;
        esp_http_client_cleanup(client);
        return false;
    }
