bool Assets::GetAssetData(const std::string& name, void*& ptr, size_t& size)
{
    // Check if the partition is valid
    if (!partition_valid_) {
        ESP_LOGE(TAG, "Partition not valid");
        return false;
    }

    // Look up the asset in our map
    auto it = assets_.find(name);
    if (it == assets_.end()) {
        ESP_LOGW(TAG, "Asset '%s' not found", name.c_str());
        return false;
    }

    const Asset& asset = it->second;

    // Calculate the actual data pointer (after header)
    const char* asset_data = mmap_root_ + asset.offset;

    // Check if we have enough data for the header
    if (asset.size < sizeof(uint32_t)) {
        ESP_LOGE(TAG, "Asset '%s' too small for header", name.c_str());
        return false;
    }

    // Read the magic number from the beginning of the asset data
    uint32_t magic_number = *(const uint32_t*)asset_data;

    // Validate magic number (assuming a specific magic number like 0x41535345 for "ASSE")
    // This is a placeholder - you'd use the actual expected magic number
    const uint32_t expected_magic = 0x41535345; // "ASSE" in little-endian

    if (magic_number != expected_magic) {
        ESP_LOGE(TAG, "Asset '%s' has invalid magic number: 0x%08x", name.c_str(), magic_number);
        return false;
    }

    // Set the output parameters
    // Skip the magic number (4 bytes) when returning the data pointer
    ptr = (void*)(asset_data + sizeof(uint32_t));
    size = asset.size - sizeof(uint32_t);

    return true;
}

