bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const {
    // Self-transitions are always valid
    if (from == to) {
        return true;
    }

    switch (from) {
        case kDeviceStateUnknown:
            // Unknown can transition to Starting
            return to == kDeviceStateStarting;

        case kDeviceStateStarting:
            // Starting can transition to WifiConfiguring, Idle, or FatalError
            return (to == kDeviceStateWifiConfiguring || 
                    to == kDeviceStateIdle || 
                    to == kDeviceStateFatalError);

        case kDeviceStateWifiConfiguring:
            // WifiConfiguring can transition to Idle, Connecting, or FatalError
            return (to == kDeviceStateIdle || 
                    to == kDeviceStateConnecting || 
                    to == kDeviceStateFatalError);

        case kDeviceStateIdle:
            // Idle can transition to many states
            return (to == kDeviceStateConnecting ||
                    to == kDeviceStateListening ||
                    to == kDeviceStateSpeaking ||
                    to == kDeviceStateUpgrading ||
                    to == kDeviceStateActivating ||
                    to == kDeviceStateAudioTesting ||
                    to == kDeviceStateFatalError);

        case kDeviceStateConnecting:
            // Connecting can transition to Listening, Idle, or FatalError
            return (to == kDeviceStateListening ||
                    to == kDeviceStateIdle ||
                    to == kDeviceStateFatalError);

        case kDeviceStateListening:
            // Listening can transition to Speaking, Idle, or FatalError
            return (to == kDeviceStateSpeaking ||
                    to == kDeviceStateIdle ||
                    to == kDeviceStateFatalError);

        case kDeviceStateSpeaking:
            // Speaking can transition to Listening, Idle, or FatalError
            return (to == kDeviceStateListening ||
                    to == kDeviceStateIdle ||
                    to == kDeviceStateFatalError);

        case kDeviceStateUpgrading:
            // Upgrading can transition to Idle or FatalError
            return (to == kDeviceStateIdle ||
                    to == kDeviceStateFatalError);

        case kDeviceStateActivating:
            // Activating can transition to Idle or FatalError
            return (to == kDeviceStateIdle ||
                    to == kDeviceStateFatalError);

        case kDeviceStateAudioTesting:
            // AudioTesting can transition to Idle or FatalError
            return (to == kDeviceStateIdle ||
                    to == kDeviceStateFatalError);

        case kDeviceStateFatalError:
            // FatalError can transition to Idle or Unknown
            return (to == kDeviceStateIdle ||
                    to == kDeviceStateUnknown);

        default:
            // All other transitions are invalid
            return false;
    }
}

