bool DeviceStateMachine::TransitionTo(DeviceState new_state) {
    // First check if the transition is valid
    if (!CanTransitionTo(new_state)) {
        ESP_LOGW(TAG, "Invalid state transition attempted: %s -> %s", 
                 GetStateName(current_state_.load()), GetStateName(new_state));
        return false;
    }

    // Get the current state before transition
    DeviceState old_state = current_state_.load();

    // Perform the state transition atomically
    current_state_.store(new_state);

    // Notify all registered listeners of the state change
    NotifyStateChange(old_state, new_state);

    ESP_LOGI(TAG, "State transition completed: %s -> %s", 
             GetStateName(old_state), GetStateName(new_state));

    return true;
}

int DeviceStateMachine::AddStateChangeListener(StateCallback callback)
{
    std::lock_guard<std::mutex> lock(mutex_);

    int listener_id = next_listener_id_++;
    listeners_.emplace_back(listener_id, callback);

    return listener_id;
}

void DeviceStateMachine::RemoveStateChangeListener(int listener_id) {
    std::lock_guard<std::mutex> lock(mutex_);

    // Remove the listener with the specified ID
    listeners_.erase(
        std::remove_if(listeners_.begin(), listeners_.end(),
            [listener_id](const std::pair<int, StateCallback>& listener) {
                return listener.first == listener_id;
            }),
        listeners_.end()
    );
}

