esp_http_client_config_t Ota::SetupHttp()
{
    esp_http_client_config_t config = {};

    // Set basic HTTP client configuration
    config.url = ota_server_url;  // Assuming this is member variable

    // Set essential headers
    std::vector<esp_http_client_header_t> headers;

    // Device identification header
    char device_id[65];
    esp_efuse_mac_get_default((uint8_t*)device_id);
    device_id[6] = '\0';  // Ensure null termination

    // User Agent header
    std::string user_agent = "ESP32-OTA-Agent/" + std::string(ESP_IDF_VERSION_MAJOR) + "." + 
                            std::string(ESP_IDF_VERSION_MINOR) + "-" + 
                            std::string(system_info_get_version());
    config.user_agent = user_agent.c_str();

    // Language header
    const char* lang = lang_config_get_current_language();
    if (lang != nullptr) {
        config.headers = new const char*[2];
        config.headers[0] = "Accept-Language: ";
        config.headers[0] += lang;
        config.headers[1] = nullptr;
    }

    // Content Type header
    config.content_type = "application/octet-stream";

    // Conditional serial number based on device provisioning status
    if (settings_is_device_provisioned()) {
        char serial_number[33];
        if (settings_get_serial_number(serial_number, sizeof(serial_number)) == ESP_OK) {
            // Add serial number to headers or URL parameters
            // This would typically be added as a custom header
            headers.push_back({"X-Device-Serial", serial_number});
        }
    }

    // Additional headers for OTA operations
    headers.push_back({"Connection", "keep-alive"});
    headers.push_back({"Cache-Control", "no-cache"});

    // Set headers in config
    config.headers = new const char*[headers.size() + 1];
    for (size_t i = 0; i < headers.size(); ++i) {
        config.headers[i] = headers[i].first;
    }
    config.headers[headers.size()] = nullptr;

    // Set timeout values
    config.timeout_ms = 30000;  // 30 seconds
    config.disable_auto_redirect = false;

    // Set certificate verification if needed
    config.crt_bundle_attach = NULL;

    return config;
}

