    // Get the URL for checking version
    std::string url = GetCheckVersionUrl();
    if (url.empty()) {
        ESP_LOGE(TAG, "Empty URL for version check");
        return ESP_ERR_INVALID_ARG;
    }

    // Make HTTP GET request
    std::string response;
    esp_err_t err = http->Get(url, &response);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "HTTP GET failed: %s", esp_err_to_name(err));
        return err;
