void Ota::MarkCurrentVersionValid()
{
    const esp_partition_t* running_partition = esp_ota_get_running_partition();
    if (running_partition == nullptr) {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    // Skip validation for factory partition
    if (running_partition->subtype == ESP_PARTITION_SUBTYPE_APP_FACTORY) {
        ESP_LOGI(TAG, "Skipping validation for factory partition");
        return;
    }

    esp_ota_state_t state;
    if (esp_ota_get_state_partition(running_partition, &state) != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get state of running partition");
        return;
    }

    ESP_LOGI(TAG, "Current partition state: %d", state);

    // Only mark as valid if in PENDING state
    if (state == ESP_OTA_STATE_PENDING_VERIFY) {
        ESP_LOGI(TAG, "Marking current version as valid");
        if (esp_ota_mark_app_valid_cancel(running_partition) != ESP_OK) {
            ESP_LOGE(TAG, "Failed to mark app as valid");
            return;
        }
        ESP_LOGI(TAG, "Successfully marked current version as valid");
    } else if (state == ESP_OTA_STATE_VALID) {
        ESP_LOGI(TAG, "Current version already marked as valid");
    } else {
        ESP_LOGI(TAG, "Current version not in pending verification state, skipping validation");
    }
}

