bool Ota::Upgrade(const std::string& firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    ESP_LOGI(TAG, "Starting firmware upgrade from %s", firmware_url.c_str());

    // Initialize variables
    esp_err_t err = ESP_OK;
    esp_ota_handle_t ota_handle = 0;
    const esp_partition_t* partition = nullptr;
    size_t total_size = 0;
    size_t downloaded_size = 0;
    uint64_t start_time = esp_timer_get_time();
    size_t last_speed_update = 0;
    int last_progress = 0;

    // Get the OTA partition
    partition = esp_ota_get_next_update_partition(NULL);
    if (partition == NULL) {
        ESP_LOGE(TAG, "No OTA partition found");
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition subtype %d at offset 0x%x",
             partition->subtype, partition->address);

    // Start OTA update
    err = esp_ota_begin(partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed, error=%d", err);
        return false;
    }

    // Setup HTTP connection
    auto http = SetupHttp();
    if (!http) {
        ESP_LOGE(TAG, "Failed to setup HTTP connection");
        esp_ota_end(ota_handle);
        return false;
    }

    // Set up progress tracking
    auto progress_callback = [&callback, &downloaded_size, &total_size, &start_time, &last_speed_update, &last_progress](
        size_t downloaded, size_t total) {
        downloaded_size = downloaded;
        total_size = total;

        // Calculate progress percentage
        int progress = total > 0 ? (int)((downloaded * 100) / total) : 0;

        // Calculate speed every 100ms
        uint64_t current_time = esp_timer_get_time();
        if (current_time - last_speed_update > 100000) { // 100ms
            size_t elapsed_ms = (current_time - start_time) / 1000;
            size_t speed = elapsed_ms > 0 ? (downloaded_size * 1000) / elapsed_ms : 0;

            if (progress != last_progress) {
                callback(progress, speed);
                last_progress = progress;
            }
            last_speed_update = current_time;
        } else if (progress != last_progress) {
            size_t elapsed_ms = (current_time - start_time) / 1000;
            size_t speed = elapsed_ms > 0 ? (downloaded_size * 1000) / elapsed_ms : 0;
            callback(progress, speed);
            last_progress = progress;
        }
    };

    // Perform HTTP download with progress tracking
    err = http->Download(firmware_url, [ota_handle, &progress_callback](const char* data, size_t len) {
        if (data && len > 0) {
            esp_err_t write_err = esp_ota_write(ota_handle, data, len);
            if (write_err != ESP_OK) {
                ESP_LOGE(TAG, "esp_ota_write failed, error=%d", write_err);
                return false;
            }
        }
        return true;
    }, progress_callback);

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "HTTP download failed, error=%d", err);
        esp_ota_end(ota_handle);
        return false;
    }

    // Finalize OTA update
    err = esp_ota_end(ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed, error=%d", err);
        return false;
    }

    // Verify the OTA partition
    err = esp_ota_set_boot_partition(partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed, error=%d", err);
        return false;
    }

    ESP_LOGI(TAG, "Firmware upgrade completed successfully");
    return true;
