bool Ota::IsNewVersionAvailable(const std::string& currentVersion, const std::string& newVersion)
{
    std::vector<int> currentParsed = ParseVersion(currentVersion);
    std::vector<int> newParsed = ParseVersion(newVersion);

    // Compare version segments one by one
    size_t minSize = std::min(currentParsed.size(), newParsed.size());

    for (size_t i = 0; i < minSize; ++i) {
        if (newParsed[i] > currentParsed[i]) {
            return true;
        }
        if (newParsed[i] < currentParsed[i]) {
            return false;
        }
        // If equal, continue to next segment
    }

    // If all compared segments are equal, the version with more segments is newer
    // For example: 1.2.3 vs 1.2.3.0 -> first is older
    // For example: 1.2.3.0 vs 1.2.3 -> second is older
    return newParsed.size() > currentParsed.size();
}

std::string Ota::GetActivationPayload()
{
    // Create JSON object for the payload
    cJSON *payload = cJSON_CreateObject();
    if (!payload) {
        return "{}";
    }

    // Get device serial number from efuse
    uint8_t serial_number[12];
    esp_err_t err = esp_efuse_read_field_blob(ESP_EFUSE_CUSTOM_UID, serial_number, sizeof(serial_number) * 8);
    if (err != ESP_OK) {
        // If we can't get the serial number, return empty JSON object
        cJSON_Delete(payload);
        return "{}";
    }

    // Convert serial number to hex string for JSON
    char serial_str[25]; // 12 bytes * 2 hex chars + null terminator
    for (int i = 0; i < 12; i++) {
        sprintf(&serial_str[i*2], "%02x", serial_number[i]);
    }

    // Add serial number to payload
    cJSON_AddStringToObject(payload, "serial_number", serial_str);

    // Add challenge string (hardcoded or generated)
    cJSON_AddStringToObject(payload, "challenge", "device_activation_challenge");

    // Generate HMAC-SHA256 signature if HMAC is supported
#ifdef SOC_HMAC_SUPPORTED
    // Get hardware-backed key (assuming it's stored in efuse)
    uint8_t hmac_key[32]; // 256-bit key
    err = esp_efuse_read_field_blob(ESP_EFUSE_KEY_PURPOSE_0, hmac_key, sizeof(hmac_key) * 8);
    if (err != ESP_OK) {
        // If we can't get the key, return empty JSON object
        cJSON_Delete(payload);
        return "{}";
    }

    // Create message to sign (serial number + challenge)
    std::string message = std::string(serial_str) + "device_activation_challenge";

    // Calculate HMAC-SHA256 signature
    uint8_t signature[32]; // SHA256 produces 32-byte hash
    err = esp_hmac_calculate(ESP_HMAC_SHA256, hmac_key, sizeof(hmac_key), 
                            (const uint8_t*)message.c_str(), message.length(), signature);
    if (err == ESP_OK) {
        // Convert signature to hex string
        char signature_str[65]; // 32 bytes * 2 hex chars + null terminator
        for (int i = 0; i < 32; i++) {
            sprintf(&signature_str[i*2], "%02x", signature[i]);
        }
        cJSON_AddStringToObject(payload, "signature", signature_str);
    } else {
        // If signature generation fails, clean up and return empty JSON
        cJSON_Delete(payload);
        return "{}";
    }
#else
    // HMAC not supported, add placeholder or skip signature
    cJSON_AddStringToObject(payload, "signature", "hmac_not_supported");
#endif

    // Convert JSON to string
    char *json_string = cJSON_Print(payload);
    if (!json_string) {
        cJSON_Delete(payload);
        return "{}";
    }

    std::string result(json_string);
    cJSON_free(json_string);
    cJSON_Delete(payload);

    return result;
}

