esp_err_t Ota::Activate()
{
    auto http = SetupHttp();
    if (!http) {
        ESP_LOGE(TAG, "Failed to setup HTTP client");
        return ESP_FAIL;
    }

    std::string url = "http://";
    // Assuming there's a method to get activation URL or it's hardcoded
    // For now, we'll construct it from existing data
    url += "your-server-domain.com"; // This would typically come from settings or config
    url += "/activate";

    std::string payload = GetActivationPayload();

    // Set headers
    http->SetHeader("Content-Type", "application/json");

    // Send POST request
    auto response = http->Post(url, payload);
    if (!response) {
        ESP_LOGE(TAG, "Failed to send activation request");
        return ESP_FAIL;
    }

    // Handle response based on HTTP status code
    switch (response->status_code) {
        case 200: // Success
            ESP_LOGI(TAG, "Activation successful");
            return ESP_OK;

        case 400: // Bad Request
            ESP_LOGE(TAG, "Activation failed - Bad Request");
            return ESP_ERR_INVALID_ARG;

        case 401: // Unauthorized
            ESP_LOGE(TAG, "Activation failed - Unauthorized");
            return ESP_ERR_UNAUTHORIZED;

        case 403: // Forbidden
            ESP_LOGE(TAG, "Activation failed - Forbidden");
            return ESP_ERR_FORBIDDEN;

        case 404: // Not Found
            ESP_LOGE(TAG, "Activation failed - Not Found");
            return ESP_ERR_NOT_FOUND;

        case 500: // Internal Server Error
            ESP_LOGE(TAG, "Activation failed - Internal Server Error");
            return ESP_ERR_INVALID_RESPONSE;

        default:
            ESP_LOGE(TAG, "Activation failed with status code: %d", response->status_code);
            return ESP_FAIL;
    }
}

