std::string Settings::GetString(const std::string& key, const std::string& default_value) {
    // First, check if we have a valid NVS handle
    if (nvs_handle_ == 0) {
        ESP_LOGE(TAG, "NVS handle is invalid");
        return default_value;
    }

    // Get the required buffer size first
    size_t required_size = 0;
    esp_err_t err = nvs_get_str(nvs_handle_, key.c_str(), nullptr, &required_size);

    // If key doesn't exist or error occurred, return default value
    if (err == ESP_ERR_NVS_NOT_FOUND) {
        ESP_LOGD(TAG, "Key '%s' not found, returning default value", key.c_str());
        return default_value;
    }

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Error getting string size for key '%s': %s", key.c_str(), esp_err_to_name(err));
        return default_value;
    }

    // If size is 0, return empty string
    if (required_size == 0) {
        return "";
    }

    // Allocate buffer for the string
    char* buffer = new char[required_size];
    if (buffer == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate buffer for key '%s'", key.c_str());
        return default_value;
    }

    // Retrieve the actual string value
    err = nvs_get_str(nvs_handle_, key.c_str(), buffer, &required_size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Error retrieving string for key '%s': %s", key.c_str(), esp_err_to_name(err));
        delete[] buffer;
        return default_value;
    }

    // Create string from buffer and remove trailing null characters
    std::string result(buffer);

    // Remove trailing null characters (though nvs_get_str should not include them)
    while (!result.empty() && result.back() == '\0') {
        result.pop_back();
    }

    delete[] buffer;
    return result;
}

bool Settings::SetString(const std::string &key, const std::string &value)
{
    if (!read_write_) {
        ESP_LOGW(TAG, "Cannot set string in read-only namespace %s", ns_.c_str());
        return false;
    }

    esp_err_t err = nvs_set_str(nvs_handle_, key.c_str(), value.c_str());
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set string for key %s: %s", key.c_str(), esp_err_to_name(err));
        return false;
    }

    // Mark settings as dirty to indicate unsaved changes
    dirty_ = true;
    return true;
}

