    esp_err_t err = nvs_erase_key(nvs_handle_, key.c_str());
    if (err == ESP_OK) {
        dirty_ = true;
    } else if (err == ESP_ERR_NVS_KEY_NOT_FOUND) {
        // Key doesn't exist, handle gracefully
        ESP_LOGD(TAG, "Key %s not found in namespace %s", key.c_str(), ns_.c_str());
    } else {
        ESP_LOGE(TAG, "Failed to erase key %s from namespace %s: %s", 
                 key.c_str(), ns_.c_str(), esp_err_to_name(err));
    }
}

