353: void McpServer::ParseMessage(const cJSON* json) {
354:     // Check JSONRPC version
355:     auto version = cJSON_GetObjectItem(json, "jsonrpc");
356:     if (version == nullptr || !cJSON_IsString(version) || strcmp(version->valuestring, "2.0") != 0) {
357:         ESP_LOGE(TAG, "Invalid JSONRPC version: %s", version ? version->valuestring : "null");
358:         return;
359:     }
360:     
361:     // Check method
362:     auto method = cJSON_GetObjectItem(json, "method");
363:     if (method == nullptr || !cJSON_IsString(method)) {
364:         ESP_LOGE(TAG, "Missing method");
365:         return;
366:     }
367:     
368:     auto method_str = std::string(method->valuestring);
369:     if (method_str.find("notifications") == 0) {
370:         return;
371:     }
372:     
373:     // Check params
374:     auto params = cJSON_GetObjectItem(json, "params");
375:     if (params != nullptr && !cJSON_IsObject(params)) {
376:         ESP_LOGE(TAG, "Invalid params for method: %s", method_str.c_str());
377:         return;
378:     }
379: 
380:     auto id = cJSON_GetObjectItem(json, "id");
381:     if (id == nullptr || !cJSON_IsNumber(id)) {
382:         ESP_LOGE(TAG, "Invalid id for method: %s", method_str.c_str());
383:         return;
384:     }
385:     auto id_int = id->valueint;
386:     
387:     if (method_str == "initialize") {
388:         if (cJSON_IsObject(params)) {
389:             auto capabilities = cJSON_GetObjectItem(params, "capabilities");
390:             if (cJSON_IsObject(capabilities)) {
391:                 ParseCapabilities(capabilities);
392:             }
393:         }
394:         auto app_desc = esp_app_get_description();
395:         std::string message = "{\"protocolVersion\":\"2024-11-05\",\"capabilities\":{\"tools\":{}},\"serverInfo\":{\"name\":\"" BOARD_NAME "\",\"version\":\"";
396:         message += app_desc->version;
397:         message += "\"}}";
398:         ReplyResult(id_int, message);
399:     } else if (method_str == "tools/list") {
400:         std::string cursor_str = "";
401:         bool list_user_only_tools = false;
402:         if (params != nullptr) {
403:             auto cursor = cJSON_GetObjectItem(params, "cursor");
404:             if (cJSON_IsString(cursor)) {
405:                 cursor_str = std::string(cursor->valuestring);
406:             }
407:             auto with_user_tools = cJSON_GetObjectItem(params, "withUserTools");
408:             if (cJSON_IsBool(with_user_tools)) {
409:                 list_user_only_tools = with_user_tools->valueint == 1;
410:             }
411:         }
412:         GetToolsList(id_int, cursor_str, list_user_only_tools);
413:     } else if (method_str == "tools/call") {
414:         if (!cJSON_IsObject(params)) {
415:             ESP_LOGE(TAG, "tools/call: Missing params");
416:             ReplyError(id_int, "Missing params");
417:             return;
418:         }
419:         auto tool_name = cJSON_GetObjectItem(params, "name");
420:         if (!cJSON_IsString(tool_name)) {
421:             ESP_LOGE(TAG, "tools/call: Missing name");
422:             ReplyError(id_int, "Missing name");
423:             return;
424:         }
425:         auto tool_arguments = cJSON_GetObjectItem(params, "arguments");
426:         if (tool_arguments != nullptr && !cJSON_IsObject(tool_arguments)) {
427:             ESP_LOGE(TAG, "tools/call: Invalid arguments");
428:             ReplyError(id_int, "Invalid arguments");
429:             return;
430:         }
431:         DoToolCall(id_int, std::string(tool_name->valuestring), tool_arguments);
432:     } else {
433:         ESP_LOGE(TAG, "Method not implemented: %s", method_str.c_str());
434:         ReplyError(id_int, "Method not implemented: " + method_str);
435:     }
436: }
