455: void McpServer::GetToolsList(int id, const std::string& cursor, bool list_user_only_tools) {
456:     const int max_payload_size = 8000;
457:     std::string json = "{\"tools\":[";
458:     
459:     bool found_cursor = cursor.empty();
460:     auto it = tools_.begin();
461:     std::string next_cursor = "";
462:     
463:     while (it != tools_.end()) {
464:         // 如果我们还没有找到起始位置，继续搜索
465:         if (!found_cursor) {
466:             if ((*it)->name() == cursor) {
467:                 found_cursor = true;
468:             } else {
469:                 ++it;
470:                 continue;
471:             }
472:         }
473: 
474:         if (!list_user_only_tools && (*it)->user_only()) {
475:             ++it;
476:             continue;
477:         }
478:         
479:         // 添加tool前检查大小
480:         std::string tool_json = (*it)->to_json() + ",";
481:         if (json.length() + tool_json.length() + 30 > max_payload_size) {
482:             // 如果添加这个tool会超出大小限制，设置next_cursor并退出循环
483:             next_cursor = (*it)->name();
484:             break;
485:         }
486:         
487:         json += tool_json;
488:         ++it;
489:     }
490:     
491:     if (json.back() == ',') {
492:         json.pop_back();
493:     }
494:     
495:     if (json.back() == '[' && !tools_.empty()) {
496:         // 如果没有添加任何tool，返回错误
497:         ESP_LOGE(TAG, "tools/list: Failed to add tool %s because of payload size limit", next_cursor.c_str());
498:         ReplyError(id, "Failed to add tool " + next_cursor + " because of payload size limit");
499:         return;
500:     }
501: 
502:     if (next_cursor.empty()) {
503:         json += "]}";
504:     } else {
505:         json += "],\"nextCursor\":\"" + next_cursor + "\"}";
506:     }
507:     
508:     ReplyResult(id, json);
509: }
