511: void McpServer::DoToolCall(int id, const std::string& tool_name, const cJSON* tool_arguments) {
512:     auto tool_iter = std::find_if(tools_.begin(), tools_.end(), 
513:                                  [&tool_name](const McpTool* tool) { 
514:                                      return tool->name() == tool_name; 
515:                                  });
516:     
517:     if (tool_iter == tools_.end()) {
518:         ESP_LOGE(TAG, "tools/call: Unknown tool: %s", tool_name.c_str());
519:         ReplyError(id, "Unknown tool: " + tool_name);
520:         return;
521:     }
522: 
523:     PropertyList arguments = (*tool_iter)->properties();
524:     try {
525:         for (auto& argument : arguments) {
526:             bool found = false;
527:             if (cJSON_IsObject(tool_arguments)) {
528:                 auto value = cJSON_GetObjectItem(tool_arguments, argument.name().c_str());
529:                 if (argument.type() == kPropertyTypeBoolean && cJSON_IsBool(value)) {
530:                     argument.set_value<bool>(value->valueint == 1);
531:                     found = true;
532:                 } else if (argument.type() == kPropertyTypeInteger && cJSON_IsNumber(value)) {
533:                     argument.set_value<int>(value->valueint);
534:                     found = true;
535:                 } else if (argument.type() == kPropertyTypeString && cJSON_IsString(value)) {
536:                     argument.set_value<std::string>(value->valuestring);
537:                     found = true;
538:                 }
539:             }
540: 
541:             if (!argument.has_default_value() && !found) {
542:                 ESP_LOGE(TAG, "tools/call: Missing valid argument: %s", argument.name().c_str());
543:                 ReplyError(id, "Missing valid argument: " + argument.name());
544:                 return;
545:             }
546:         }
547:     } catch (const std::exception& e) {
548:         ESP_LOGE(TAG, "tools/call: %s", e.what());
549:         ReplyError(id, e.what());
550:         return;
551:     }
552: 
553:     // Use main thread to call the tool
554:     auto& app = Application::GetInstance();
555:     app.Schedule([this, id, tool_iter, arguments = std::move(arguments)]() {
556:         try {
557:             ReplyResult(id, (*tool_iter)->Call(arguments));
558:         } catch (const std::exception& e) {
559:             ESP_LOGE(TAG, "tools/call: %s", e.what());
560:             ReplyError(id, e.what());
561:         }
562:     });
563: }
