    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);

    switch (chip_info.model) {
        case CHIP_ESP32:
            chip_model = "ESP32";
            break;
        case CHIP_ESP32S2:
            chip_model = "ESP32-S2";
            break;
        case CHIP_ESP32S3:
            chip_model = "ESP32-S3";
            break;
        case CHIP_ESP32C3:
            chip_model = "ESP32-C3";
            break;
        case CHIP_ESP32C2:
            chip_model = "ESP32-C2";
            break;
        case CHIP_ESP32H2:
            chip_model = "ESP32-H2";
            break;
        case CHIP_ESP32P4:
            chip_model = "ESP32-P4";
            break;
        default:
            chip_model = "ESP32";
            break;
    }

    return std::string(chip_model);
}

std::string SystemInfo::GetUserAgent() {
    const esp_app_desc_t* app_desc = esp_app_get_description();
    if (app_desc == nullptr) {
        return std::string(BOARD_NAME "/unknown");
    }
    return std::string(BOARD_NAME "/" + std::string(app_desc->version));
}

