esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait) {
    // Define constants
    const int ARRAY_SIZE_OFFSET = 10; // Extra space for potential new tasks

    // Get initial task count and allocate memory for task status array
    UBaseType_t start_array_size = uxTaskGetNumberOfTasks() + ARRAY_SIZE_OFFSET;
    TaskStatus_t *start_array = (TaskStatus_t *)malloc(sizeof(TaskStatus_t) * start_array_size);

    if (start_array == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for start task array");
        return ESP_FAIL;
    }

    // Get initial task statuses
    UBaseType_t start_task_count = uxTaskGetSystemState(start_array, start_array_size, &total_elapsed_time);

    // Wait for specified time interval
    vTaskDelay(xTicksToWait);

    // Get final task count and statuses
    UBaseType_t end_array_size = uxTaskGetNumberOfTasks() + ARRAY_SIZE_OFFSET;
    TaskStatus_t *end_array = (TaskStatus_t *)malloc(sizeof(TaskStatus_t) * end_array_size);

    if (end_array == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for end task array");
        free(start_array);
        return ESP_FAIL;
    }

    UBaseType_t end_task_count = uxTaskGetSystemState(end_array, end_array_size, NULL);

    // Calculate CPU usage for each task
    ESP_LOGI(TAG, "Task CPU Usage Report:");
    ESP_LOGI(TAG, "Task Name           CPU Usage (%)");
    ESP_LOGI(TAG, "------------------- -------------");

    // Create a map to track tasks by their unique identifiers
    for (UBaseType_t i = 0; i < start_task_count; i++) {
        TaskHandle_t task_handle = start_array[i].xHandle;

        // Find corresponding task in end array
        for (UBaseType_t j = 0; j < end_task_count; j++) {
            if (end_array[j].xHandle == task_handle) {
                // Calculate CPU usage
                uint32_t start_run_time = start_array[i].ulRunTimeCounter;
                uint32_t end_run_time = end_array[j].ulRunTimeCounter;

                // Calculate difference in run time
                uint32_t run_time_diff = end_run_time - start_run_time;

                // Calculate CPU percentage
                float cpu_percentage = (float)(run_time_diff * 100.0f) / (float)total_elapsed_time;

                // Print task information
                ESP_LOGI(TAG, "%-20s %.2f%%", start_array[i].pcTaskName, cpu_percentage);
                break;
            }
        }
    }

    // Check for newly created tasks
    ESP_LOGI(TAG, "\nNewly Created Tasks:");
    for (UBaseType_t i = 0; i < end_task_count; i++) {
        bool found = false;
        for (UBaseType_t j = 0; j < start_task_count; j++) {
            if (end_array[i].xHandle == start_array[j].xHandle) {
                found = true;
                break;
            }
        }
        if (!found) {
            ESP_LOGI(TAG, "New task created: %s", end_array[i].pcTaskName);
        }
    }

    // Check for deleted tasks
    ESP_LOGI(TAG, "\nDeleted Tasks:");
    for (UBaseType_t i = 0; i < start_task_count; i++) {
        bool found = false;
        for (UBaseType_t j = 0; j < end_task_count; j++) {
            if (start_array[i].xHandle == end_array[j].xHandle) {
                found = true;
                break;
            }
        }
        if (!found) {
            ESP_LOGI(TAG, "Task deleted: %s", start_array[i].pcTaskName);
        }
    }

    // Free allocated memory
    free(start_array);
    free(end_array);

    return ESP_OK;
}

void SystemInfo::PrintTaskList() {
    // Get the number of tasks currently running
    UBaseType_t numberOfTasks = uxTaskGetNumberOfTasks();

    // Allocate memory for task status array
    TaskStatus_t *pxTaskStatusArray;
    pxTaskStatusArray = (TaskStatus_t *)malloc(sizeof(TaskStatus_t) * numberOfTasks);

    if (pxTaskStatusArray == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task status array");
        return;
    }

    // Get the task list
    UBaseType_t uxArraySize = vTaskList(pxTaskStatusArray);

    // Log the task information
    ESP_LOGI(TAG, "Task List:");
    ESP_LOGI(TAG, "Name                   State   Prio    Stack   Num");
    ESP_LOGI(TAG, "----------------------------------------");

    for (UBaseType_t x = 0; x < uxArraySize; x++) {
        char state_char;
        switch (pxTaskStatusArray[x].eCurrentState) {
            case eRunning:
                state_char = 'R';
                break;
            case eReady:
                state_char = 'R';
                break;
            case eBlocked:
                state_char = 'B';
                break;
            case eSuspended:
                state_char = 'S';
                break;
            case eDeleted:
                state_char = 'D';
                break;
            default:
                state_char = '?';
                break;
        }

        ESP_LOGI(TAG, "%-20s %c       %d       %d       %d",
                 pxTaskStatusArray[x].pcTaskName,
                 state_char,
                 pxTaskStatusArray[x].uxCurrentPriority,
                 pxTaskStatusArray[x].usStackHighWaterMark,
                 pxTaskStatusArray[x].xTaskNumber);
    }

    // Free the allocated memory
    free(pxTaskStatusArray);
}

