void AudioCodec::Start()
{
    ESP_LOGD(TAG, "Starting audio codec");

    // Configure I2S transmit handle if not already configured
    if (tx_handle_ == nullptr) {
        i2s_chan_config_t tx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
        tx_chan_cfg.dma_desc_num = AUDIO_CODEC_DMA_DESC_NUM;
        tx_chan_cfg.dma_frame_num = AUDIO_CODEC_DMA_FRAME_NUM;

        esp_err_t ret = i2s_new_channel(&tx_chan_cfg, &tx_handle_, NULL);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to create I2S TX channel: %s", esp_err_to_name(ret));
            return;
        }
    }

    // Configure I2S receive handle if not already configured
    if (rx_handle_ == nullptr) {
        i2s_chan_config_t rx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
        rx_chan_cfg.dma_desc_num = AUDIO_CODEC_DMA_DESC_NUM;
        rx_chan_cfg.dma_frame_num = AUDIO_CODEC_DMA_FRAME_NUM;

        esp_err_t ret = i2s_new_channel(&rx_chan_cfg, NULL, &rx_handle_);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to create I2S RX channel: %s", esp_err_to_name(ret));
            return;
        }
    }

    // Apply output volume settings
    SetOutputVolume(output_volume_);

    // Apply input gain settings
    SetInputGain(input_gain_);

    // Enable input and output channels
    EnableInput(true);
    EnableOutput(true);

    ESP_LOGD(TAG, "Audio codec started successfully");
}

