#include "es8388_audio_codec.h"

#include <esp_log.h>
#include <esp_codec_dev.h>
#include <esp_codec_dev_defaults.h>

#define TAG "Es8388AudioCodec"

Es8388AudioCodec::Es8388AudioCodec(void* i2c_master_handle, i2c_port_t i2c_port, int input_sample_rate, int output_sample_rate,
                                   gpio_num_t mclk, gpio_num_t bclk, gpio_num_t ws, gpio_num_t dout, gpio_num_t din,
                                   gpio_num_t pa_pin, uint8_t es8388_addr, bool input_reference) {
    ESP_LOGD(TAG, "Initializing ES8388 Audio Codec");

    // Store GPIO pin for power amplifier control
    pa_pin_ = pa_pin;

    // Configure I2C control interface
    audio_codec_ctrl_if_t ctrl_if = {
        .i2c_handle = i2c_master_handle,
        .i2c_port = i2c_port,
        .codec_addr = es8388_addr,
    };
    ctrl_if_ = &ctrl_if;

    // Create duplex channels for full-duplex operation
    CreateDuplexChannels(mclk, bclk, ws, dout, din);

    // Configure output device
    esp_codec_dev_cfg_t output_cfg = ESP_CODEC_DEV_DEFAULT_CONFIG();
    output_cfg.codec_mode = ESP_CODEC_DEV_MODE_PLAYBACK;
    output_cfg.ctrl_if = ctrl_if_;
    output_cfg.data_if = data_if_;
    output_cfg.sample_rate = output_sample_rate;
    output_cfg.bits_per_sample = 16;
    output_cfg.channels = 2;

    output_dev_ = esp_codec_dev_new(&output_cfg);
    if (output_dev_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create output device");
        return;
    }

    // Configure input device
    esp_codec_dev_cfg_t input_cfg = ESP_CODEC_DEV_DEFAULT_CONFIG();
