    // Configure I2S master settings for full-duplex operation
    i2s_std_config_t i2s_config = {
        .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(48000),  // Standard clock config for 48kHz sample rate
        .slot_cfg = I2S_STD_PHILIPS_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
        .gpio_cfg = {
            .mclk = mclk,
            .bclk = bclk,
            .ws = ws,
            .dout = dout,
            .din = din,
        },
    };

    // Configure output device (transmit path)
    esp_codec_dev_cfg_t output_codec_cfg = {
        .dev_type = ESP_CODEC_DEV_TYPE_OUT,
        .iface = {
            .type = ESP_CODEC_DEV_IFACE_I2S,
            .i2s = {
                .config = &i2s_config,
                .port = 0,  // I2S port number, typically 0 or 1
            },
        },
        .codec = NULL,
    };

    // Configure input device (receive path)
    esp_codec_dev_cfg_t input_codec_cfg = {
        .dev_type = ESP_CODEC_DEV_TYPE_IN,
        .iface = {
