                .port = 0,  // I2S port number, typically 0 or 1
            },
        },
        .codec = NULL,
    };

    // Initialize output device
    esp_err_t ret = esp_codec_dev_init(output_dev_, &output_codec_cfg);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize output codec device");
