void Es8388AudioCodec::SetOutputVolume(int volume) {
    // Validate volume range (assuming 0-100%)
    if (volume < 0) volume = 0;
    if (volume > 100) volume = 100;

    // Lock mutex for thread safety
    std::lock_guard<std::mutex> lock(data_if_mutex_);

    // Use the codec device to set output volume
    if (output_dev_ != nullptr) {
        // Convert percentage to appropriate format for codec
        // ES8388 typically uses 0-127 range for volume control
        int codec_volume = volume * 127 / 100;

        // Set volume on output device
        esp_err_t err = esp_codec_dev_set_out_vol(output_dev_, codec_volume);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to set output volume: %s", esp_err_to_name(err));
        } else {
            ESP_LOGD(TAG, "Output volume set to %d%%", volume);
        }
    } else {
        ESP_LOGW(TAG, "Output device not initialized");
    }
}

