    ESP_LOGD(TAG, "EnableInput: %s", enable ? "true" : "false");

    if (enable) {
        // Enable input - configure and open input device
        if (input_dev_ == nullptr) {
            // Configure input device settings
            esp_codec_dev_cfg_t input_codec_cfg = {
                .dev_type = ESP_CODEC_DEV_TYPE_IN,
                .codec_mode = ESP_CODEC_DEV_MODE_BOTH,
                .i2c_cfg = {
                    .port = i2c_port_,
                    .addr = es8388_addr_,
                    .master_handle = (i2c_master_bus_handle_t)i2c_master_handle_,
                },
                .data_if = data_if_,
                .ctrl_if = ctrl_if_,
                .gpio_if = gpio_if_,
            };

            // Create input device
            input_dev_ = esp_codec_dev_new(&input_codec_cfg);
            if (input_dev_ == nullptr) {
                ESP_LOGE(TAG, "Failed to create input codec device");
                return;
            }

            // Configure input parameters
            esp_codec_dev_set_sample_rate(input_dev_, input_sample_rate_);
            esp_codec_dev_set_bits_per_sample(input_dev_, 16);  // Assuming 16-bit depth
            esp_codec_dev_set_channels(input_dev_, 2);          // Assuming stereo

            // Apply input gain (fixed or adjustable)
            // For now, applying a default gain value - this could be made configurable
            esp_codec_dev_set_gain(input_dev_, 20);  // Example gain value

            // Open the input device
            esp_err_t ret = esp_codec_dev_open(input_dev_);
            if (ret != ESP_OK) {
                ESP_LOGE(TAG, "Failed to open input codec device: %d", ret);
                esp_codec_dev_destroy(input_dev_);
                input_dev_ = nullptr;
                return;
            }

            ESP_LOGI(TAG, "Input enabled successfully");
        }
    } else {
        // Disable input - close input device
        if (input_dev_ != nullptr) {
            esp_err_t ret = esp_codec_dev_close(input_dev_);
            if (ret != ESP_OK) {
                ESP_LOGW(TAG, "Failed to close input codec device: %d", ret);
            }

            // Destroy the input device handle
            esp_codec_dev_destroy(input_dev_);
            input_dev_ = nullptr;

            ESP_LOGI(TAG, "Input disabled successfully");
        }
    }
}

