    ESP_LOGD(TAG, "EnableOutput: %s", enable ? "true" : "false");

    std::lock_guard<std::mutex> lock(data_if_mutex_);

    if (enable) {
        // Enable output - configure codec and activate amplifier
        if (output_dev_) {
            // Set the output sample rate
            esp_codec_dev_set_clk(output_dev_, output_sample_rate_);

