            SetOutputVolume(50); // Assuming 50 as default volume

            // Configure analog output levels (this would typically involve register writes)
            // For now, we'll assume the codec handles this through the device interface

            // Activate power amplifier if pin is configured
            if (pa_pin_ != GPIO_NUM_NC) {
                gpio_set_direction(pa_pin_, GPIO_MODE_OUTPUT);
                gpio_set_level(pa_pin_, 1); // Enable amplifier
            }

            // Start the output device
            esp_codec_dev_open(output_dev_);
        }
    } else {
        // Disable output - close device and deactivate amplifier
        if (output_dev_) {
            // Close the output device
            esp_codec_dev_close(output_dev_);

            // Deactivate power amplifier if pin is configured
            if (pa_pin_ != GPIO_NUM_NC) {
                gpio_set_level(pa_pin_, 0); // Disable amplifier
            }
        }
    }
