    if (dest == nullptr || samples <= 0) {
        ESP_LOGE(TAG, "Invalid parameters for Read");
        return 0;
    }

    // Check if input is enabled
    if (input_dev_ == nullptr) {
        ESP_LOGW(TAG, "Input device not initialized");
        return 0;
    }

    // Perform the read operation using the codec device API
    size_t bytes_read = 0;
    esp_err_t ret = esp_codec_dev_read(input_dev_, dest, samples * sizeof(int16_t), &bytes_read);

    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read from input device: %s", esp_err_to_name(ret));
        return 0;
    }

    // Return the number of samples read (convert bytes to samples)
    return bytes_read / sizeof(int16_t);
}

