void AudioDebugger::Feed(const std::vector<int16_t>& data)
{
    if (udp_sockfd_ < 0) {
        ESP_LOGE(TAG, "UDP socket not initialized");
        return;
    }

    if (data.empty()) {
        ESP_LOGW(TAG, "Empty audio data received");
        return;
    }

    ssize_t bytes_sent = sendto(udp_sockfd_, 
                               data.data(), 
                               data.size() * sizeof(int16_t), 
                               0, 
                               (struct sockaddr*)&udp_server_addr_, 
                               sizeof(udp_server_addr_));

    if (bytes_sent < 0) {
        ESP_LOGE(TAG, "Failed to send audio data over UDP: %s", strerror(errno));
    } else {
        ESP_LOGD(TAG, "Sent %zd bytes of audio data over UDP", bytes_sent);
    }
}
