bool AfeWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* models_list) {
    ESP_LOGD(TAG, "Initializing AFE wake word detection");

    // Store codec and models
    codec_ = codec;
    models_ = models_list;

    // Initialize event group
    event_group_ = xEventGroupCreate();
    if (!event_group_) {
        ESP_LOGE(TAG, "Failed to create event group");
        return false;
    }

    // Configure audio codec
    if (!codec_->Configure()) {
        ESP_LOGE(TAG, "Failed to configure audio codec");
        return false;
    }

    // Load wake word models
    if (models_list == nullptr) {
        ESP_LOGE(TAG, "Models list is null");
        return false;
    }

    // Initialize AFE interface and data structures
    const esp_afe_sr_iface_t* afe_iface = esp_afe_sr_get_interface();
    if (!afe_iface) {
        ESP_LOGE(TAG, "Failed to get AFE SR interface");
        return false;
    }

    afe_iface_ = afe_iface;

    // Allocate AFE data structure
    afe_data_ = (esp_afe_sr_data_t*)malloc(sizeof(esp_afe_sr_data_t));
    if (!afe_data_) {
        ESP_LOGE(TAG, "Failed to allocate AFE data");
        return false;
    }

    // Initialize AFE with models
    esp_err_t err = afe_iface->init(afe_data_, models_list);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize AFE: %s", esp_err_to_name(err));
        free(afe_data_);
        afe_data_ = nullptr;
        return false;
    }

    // Set up echo cancellation
    err = afe_iface->set_echo_cancellation(afe_data_, true);
    if (err != ESP_OK) {
        ESP_LOGW(TAG, "Failed to enable echo cancellation: %s", esp_err_to_name(err));
        // Continue without echo cancellation, it's not critical
    }

    // Allocate memory for wake word PCM data
    wake_word_pcm_.reserve(10); // Reserve space for 10 buffers

    // Allocate memory for wake word OPUS data
    wake_word_opus_.reserve(10); // Reserve space for 10 buffers

    // Create static task for wake word encoding
    wake_word_encode_task_buffer_ = (StaticTask_t*)malloc(sizeof(StaticTask_t));
    wake_word_encode_task_stack_ = (StackType_t*)malloc(configMINIMAL_STACK_SIZE * sizeof(StackType_t));

    if (!wake_word_encode_task_buffer_ || !wake_word_encode_task_stack_) {
        ESP_LOGE(TAG, "Failed to allocate task resources");
        if (wake_word_encode_task_buffer_) {
            free(wake_word_encode_task_buffer_);
        }
        if (wake_word_encode_task_stack_) {
            free(wake_word_encode_task_stack_);
        }
        return false;
    }

    // Create the task
    wake_word_encode_task_ = xTaskCreateStatic(
        [](void* arg) {
            AfeWakeWord* afe_wake_word = static_cast<AfeWakeWord*>(arg);
            afe_wake_word->EncodeWakeWordData();
        },
        "wake_word_encode",
        configMINIMAL_STACK_SIZE,
        this,
        tskIDLE_PRIORITY + 1,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (!wake_word_encode_task_) {
        ESP_LOGE(TAG, "Failed to create wake word encode task");
        free(wake_word_encode_task_buffer_);
        free(wake_word_encode_task_stack_);
        wake_word_encode_task_buffer_ = nullptr;
        wake_word_encode_task_stack_ = nullptr;
        return false;
    }

    ESP_LOGD(TAG, "AFE wake word initialization completed successfully");
    return true;
}

