void AfeWakeWord::Stop() {
    // Clear the detection running event flag
    if (event_group_ != nullptr) {
        xEventGroupClearBits(event_group_, DETECTION_RUNNING_EVENT);
    }

    // Reset the audio front-end buffer if initialized
    if (afe_data_ != nullptr) {
        // Reset the audio front-end data structure
        memset(afe_data_, 0, sizeof(esp_afe_sr_data_t));
    }

    // Clear the wake word PCM buffer
    {
        std::lock_guard<std::mutex> lock(wake_word_mutex_);
        wake_word_pcm_.clear();
        wake_word_opus_.clear();
    }
}

