void AfeWakeWord::AudioDetectionTask() {
    ESP_LOGI(TAG, "Audio detection task started");

    // Initialize the acoustic front-end
    if (afe_iface_ && afe_data_) {
        // Start the detection process
        esp_err_t err = afe_iface_->start(afe_data_);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to start AFE detection: %s", esp_err_to_name(err));
            vTaskDelete(NULL);
            return;
        }

        // Main detection loop
        while (true) {
            // Wait for detection event or stop event
            EventBits_t bits = xEventGroupWaitBits(event_group_, 
                                                  DETECTION_RUNNING_EVENT, 
                                                  pdTRUE, 
                                                  pdFALSE, 
                                                  portMAX_DELAY);

            if (!(bits & DETECTION_RUNNING_EVENT)) {
                continue; // No detection running, continue waiting
            }

            // Check for wake word detection
            int detection_result = afe_iface_->detect(afe_data_);

            if (detection_result > 0) {
                // Wake word detected
                ESP_LOGI(TAG, "Wake word detected");

                // Stop the detection process
                afe_iface_->stop(afe_data_);

                // Get the detected wake word
                const char* detected_wake_word = afe_iface_->get_wake_word(afe_data_);
                if (detected_wake_word) {
                    last_detected_wake_word_ = std::string(detected_wake_word);

                    // Store the wake word data
                    if (afe_data_ && afe_data_->data && afe_data_->size > 0) {
                        StoreWakeWordData(static_cast<const int16_t*>(afe_data_->data), 
                                        afe_data_->size / sizeof(int16_t));
                    }

                    // Trigger the callback
                    if (wake_word_detected_callback_) {
                        wake_word_detected_callback_(last_detected_wake_word_);
                    }
                }

                // Reset the detection
                afe_iface_->reset(afe_data_);

                // Wait a bit before restarting detection
                vTaskDelay(pdMS_TO_TICKS(100));

                // Restart detection
                afe_iface_->start(afe_data_);
            }

            // Small delay to prevent excessive CPU usage
            vTaskDelay(pdMS_TO_TICKS(10));
        }
    } else {
        ESP_LOGE(TAG, "AFE interface or data not initialized");
    }

    vTaskDelete(NULL);
}

