void AfeWakeWord::StoreWakeWordData(const int16_t* data, size_t size) {
    // Convert raw data to vector
    std::vector<int16_t> pcm_data(data, data + size);

    // Lock the mutex for thread safety
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Add new data to the deque
    wake_word_pcm_.push_back(pcm_data);

    // Calculate approximate number of samples for 2 seconds
    // Assuming 16kHz sample rate (common for voice applications)
    const size_t samples_per_second = 16000;
    const size_t max_samples = samples_per_second * 2; // 2 seconds

    // Remove old data if we exceed the limit
    while (wake_word_pcm_.size() > 0) {
        size_t total_samples = 0;
        for (const auto& segment : wake_word_pcm_) {
            total_samples += segment.size();
        }

        if (total_samples <= max_samples) {
            break;
        }

        // Remove the oldest segment
        wake_word_pcm_.pop_front();
    }
}

