void AfeWakeWord::EncodeWakeWordData() {
    // Create the encoding task using static allocation
    wake_word_encode_task_buffer_ = new StaticTask_t;
    wake_word_encode_task_stack_ = new StackType_t[configMINIMAL_STACK_SIZE * 2];

    wake_word_encode_task_ = xTaskCreateStatic(
        [](void *arg) {
            AfeWakeWord *afe_wake_word = static_cast<AfeWakeWord*>(arg);

            // Initialize Opus encoder with low complexity settings
            OpusEncoder *encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, NULL);
            if (!encoder) {
                ESP_LOGE(TAG, "Failed to create Opus encoder");
                vTaskDelete(NULL);
                return;
            }

            // Set encoder parameters for low complexity and fast encoding
            opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));
            opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000)); // 24 kbps

            while (true) {
                // Wait for PCM data to be available or timeout
                std::unique_lock<std::mutex> lock(afe_wake_word->wake_word_mutex_);

                // Check if there's PCM data ready to encode
                if (afe_wake_word->wake_word_pcm_.empty()) {
                    // Wait for data or timeout
                    afe_wake_word->wake_word_cv_.wait_for(lock, std::chrono::milliseconds(100));
                }

                // Process all available PCM data
                while (!afe_wake_word->wake_word_pcm_.empty()) {
                    auto pcm_data = afe_wake_word->wake_word_pcm_.front();
                    afe_wake_word->wake_word_pcm_.pop_front();

                    lock.unlock();

                    // Encode PCM data to Opus
                    std::vector<uint8_t> opus_data(pcm_data.size() * 2); // Allocate enough space
                    int opus_size = opus_encode(encoder, 
                                               pcm_data.data(), 
                                               pcm_data.size(), 
                                               opus_data.data(), 
                                               opus_data.size());

                    if (opus_size > 0) {
                        // Resize to actual encoded size
                        opus_data.resize(opus_size);

                        // Store encoded data in thread-safe buffer
                        lock.lock();
                        afe_wake_word->wake_word_opus_.push_back(std::move(opus_data));
                        lock.unlock();

                        // Signal completion
                        afe_wake_word->wake_word_cv_.notify_one();
                    } else {
                        ESP_LOGE(TAG, "Opus encoding failed with error: %d", opus_size);
                    }

                    lock.lock();
                }

                lock.unlock();

                // Small delay to prevent busy waiting
                vTaskDelay(pdMS_TO_TICKS(10));
            }

            // Cleanup
            opus_encoder_destroy(encoder);
            vTaskDelete(NULL);
        },
        "wake_word_encode",
        configMINIMAL_STACK_SIZE * 2,
        this,
        tskIDLE_PRIORITY + 1,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );
}

