bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t>& opus) {
    // Lock the mutex to ensure thread-safe access to the queue
    std::unique_lock<std::mutex> lock(wake_word_queue_mutex_);

    // Wait until there is data available in the queue
    // The condition variable will be notified when new data arrives
    wake_word_queue_cv_.wait(lock, [this]() {
        return !wake_word_queue_.empty();
    });

    // Check if queue is not empty (should always be true due to wait above)
    if (!wake_word_queue_.empty()) {
        // Retrieve the front element from the queue
        opus = std::move(wake_word_queue_.front());
        wake_word_queue_.pop();

        // Unlock the mutex before returning
        lock.unlock();

        // Return true indicating successful retrieval
        return true;
    }

    // Unlock the mutex and return false if queue is empty
    lock.unlock();
    return false;
}

