CustomWakeWord::~CustomWakeWord()
{
    // Destroy the multinet model
    if (multinet_ != nullptr) {
        esp_mn_iface_delete(multinet_);
        multinet_ = nullptr;
    }

    // Free model data
    if (multinet_model_data_ != nullptr) {
        // Note: The exact cleanup method for model data depends on the ESP-MN library implementation
        // Usually this would be handled by the iface_delete call above, but we'll be safe
        multinet_model_data_ = nullptr;
    }

    // Free models list
    if (models_ != nullptr) {
        // Note: Need to check if there's a specific function to free srmodel_list_t
        // For now, we'll just nullify the pointer
        models_ = nullptr;
    }

    // Free multinet name string
    if (mn_name_ != nullptr) {
        free(mn_name_);
        mn_name_ = nullptr;
    }

    // Delete the task if it exists
    if (wake_word_encode_task_ != nullptr) {
        vTaskDelete(wake_word_encode_task_);
        wake_word_encode_task_ = nullptr;
    }

    // Free task buffer if allocated
    if (wake_word_encode_task_buffer_ != nullptr) {
        free(wake_word_encode_task_buffer_);
        wake_word_encode_task_buffer_ = nullptr;
    }

    // Free task stack if allocated
    if (wake_word_encode_task_stack_ != nullptr) {
        free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
    }

    // Clear the command list
    commands_.clear();

    // Clear PCM and OPUS queues
    while (!wake_word_pcm_.empty()) {
        wake_word_pcm_.pop_front();
    }

    while (!wake_word_opus_.empty()) {
        wake_word_opus_.pop_front();
    }
}

