void CustomWakeWord::ParseWakenetModelConfig() {
    // Load the index.json file from assets
    const char* config_data = get_asset("index.json");
    if (!config_data) {
        ESP_LOGE(TAG, "Failed to load index.json from assets");
        return;
    }

    // Parse the JSON data
    cJSON* json_root = cJSON_Parse(config_data);
    if (!json_root) {
        ESP_LOGE(TAG, "Failed to parse index.json");
        return;
    }

    // Extract language
    cJSON* language_item = cJSON_GetObjectItem(json_root, "language");
    if (language_item && cJSON_IsString(language_item)) {
        language_ = language_item->valuestring;
        ESP_LOGI(TAG, "Language set to: %s", language_.c_str());
    }

    // Extract duration
    cJSON* duration_item = cJSON_GetObjectItem(json_root, "duration");
    if (duration_item && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valueint;
        ESP_LOGI(TAG, "Duration set to: %d ms", duration_);
    }

    // Extract threshold
    cJSON* threshold_item = cJSON_GetObjectItem(json_root, "threshold");
    if (threshold_item && cJSON_IsNumber(threshold_item)) {
        threshold_ = threshold_item->valuedouble;
        ESP_LOGI(TAG, "Threshold set to: %.3f", threshold_);
    }

    // Extract commands array
    cJSON* commands_item = cJSON_GetObjectItem(json_root, "commands");
    if (commands_item && cJSON_IsArray(commands_item)) {
        int num_commands = cJSON_GetArraySize(commands_item);
        ESP_LOGI(TAG, "Found %d commands", num_commands);

        // Clear existing commands
        commands_.clear();

        // Parse each command
        for (int i = 0; i < num_commands; i++) {
            cJSON* command_obj = cJSON_GetArrayItem(commands_item, i);
            if (!command_obj) continue;

            Command cmd;

            // Extract command name
            cJSON* cmd_item = cJSON_GetObjectItem(command_obj, "command");
            if (cmd_item && cJSON_IsString(cmd_item)) {
                cmd.command = cmd_item->valuestring;
            }

            // Extract text
            cJSON* text_item = cJSON_GetObjectItem(command_obj, "text");
            if (text_item && cJSON_IsString(text_item)) {
                cmd.text = text_item->valuestring;
            }

            // Extract action
            cJSON* action_item = cJSON_GetObjectItem(command_obj, "action");
            if (action_item && cJSON_IsString(action_item)) {
                cmd.action = action_item->valuestring;
            }

            // Add to commands list
            commands_.push_back(cmd);

            // Log the parsed command
            ESP_LOGD(TAG, "Parsed command - Command: %s, Text: %s, Action: %s", 
                    cmd.command.c_str(), cmd.text.c_str(), cmd.action.c_str());
        }
    }

    // Clean up JSON parser
    cJSON_Delete(json_root);
}

