    if (!mn_iface) {
        ESP_LOGE(TAG, "Failed to get multinet interface");
        return false;
    }

    // Find the appropriate model based on language
    const char* model_name = nullptr;
    if (language_ == "cn") {
        model_name = ESP_MN_MODEL_CN;
    } else if (language_ == "en") {
        model_name = ESP_MN_MODEL_EN;
    } else {
        model_name = ESP_MN_MODEL_CN; // Default to Chinese
    }

    // Load the model
    multinet_model_data_ = esp_mn_load(mn_iface, model_name);
    if (!multinet_model_data_) {
        ESP_LOGE(TAG, "Failed to load multinet model: %s", model_name);
        return false;
