void CustomWakeWord::Feed(const std::vector<int16_t>& data)
{
    if (!running_.load() || multinet_ == nullptr) {
        return;
    }

    // Extract left channel if stereo input (assuming 2 channels)
    std::vector<int16_t> mono_data;
    if (data.size() % 2 == 0) {
        // Stereo input, extract left channel
        mono_data.reserve(data.size() / 2);
        for (size_t i = 0; i < data.size(); i += 2) {
            mono_data.push_back(data[i]);
        }
    } else {
        // Mono input or odd number of samples, use as-is
        mono_data = data;
    }

    // Store the audio data
    StoreWakeWordData(mono_data);

    // Run wake word detection
    int result = multinet_->run(multinet_model_data_, mono_data.data());

    // Check if wake word was detected
    if (result >= 0 && wake_word_detected_callback_) {
        // Get the detected wake word from the model
        const char* detected_wake_word = multinet_->get_label(multinet_model_data_, result);
        if (detected_wake_word != nullptr) {
            last_detected_wake_word_ = std::string(detected_wake_word);
            wake_word_detected_callback_(last_detected_wake_word_);

            // Stop processing until reactivated
            running_ = false;
        }
    }
}

