void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t>& data) {
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Add the new data chunk to the front of the deque
    wake_word_pcm_.push_front(data);

    // Calculate total samples and remove old chunks if needed
    // Assuming 16000 Hz sample rate for 2 seconds = 32000 samples
    // This is a reasonable assumption for voice applications
    const int SAMPLE_RATE = 16000;
    const int MAX_SAMPLES = SAMPLE_RATE * 2; // 2 seconds

    int total_samples = 0;
    auto it = wake_word_pcm_.begin();

    // Count samples and remove chunks until we're within the limit
    while (it != wake_word_pcm_.end()) {
        total_samples += it->size();
        if (total_samples > MAX_SAMPLES) {
            // Remove the oldest chunk(s) until we're under the limit
            wake_word_pcm_.pop_back();
            break;
        }
        ++it;
    }

    // If we still have more than 2 seconds worth of data, remove excess
    while (!wake_word_pcm_.empty()) {
        total_samples = 0;
        for (const auto& chunk : wake_word_pcm_) {
            total_samples += chunk.size();
        }
        if (total_samples <= MAX_SAMPLES) {
            break;
        }
        wake_word_pcm_.pop_back();
    }
}

