void CustomWakeWord::EncodeWakeWordData() {
    // Check if task is already running
    if (wake_word_encode_task_ != nullptr) {
        ESP_LOGW(TAG, "Encode task already running");
        return;
    }

    // Allocate memory for task if not already allocated
    if (wake_word_encode_task_buffer_ == nullptr) {
        wake_word_encode_task_buffer_ = new StaticTask_t;
    }

    if (wake_word_encode_task_stack_ == nullptr) {
        wake_word_encode_task_stack_ = new StackType_t[configMINIMAL_STACK_SIZE * 4]; // 4x minimum stack size
    }

    // Create the task
    wake_word_encode_task_ = xTaskCreateStatic(
        [](void* arg) {
            CustomWakeWord* self = static_cast<CustomWakeWord*>(arg);

            // Process all PCM segments
            std::vector<std::vector<int16_t>> pcm_segments;
            {
                std::lock_guard<std::mutex> lock(self->wake_word_mutex_);
                pcm_segments = std::move(self->wake_word_pcm_);
                self->wake_word_pcm_.clear();
            }

            // Initialize Opus encoder
            opus_int32 error;
            OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, &error);
            if (error != OPUS_OK || encoder == nullptr) {
                ESP_LOGE(TAG, "Failed to create Opus encoder: %d", error);
                vTaskDelete(NULL);
                return;
            }

            // Set encoder parameters for low complexity
            opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));
            opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000)); // 24 kbps

            // Process each PCM segment
            for (const auto& pcm_segment : pcm_segments) {
                if (pcm_segment.empty()) continue;

                // Prepare output buffer
                std::vector<uint8_t> opus_buffer(1024); // 1KB buffer
                int opus_len = opus_encode(encoder, 
                                          pcm_segment.data(), 
                                          pcm_segment.size(), 
                                          opus_buffer.data(), 
                                          opus_buffer.size());

                if (opus_len > 0) {
                    // Resize buffer to actual encoded size
                    opus_buffer.resize(opus_len);

                    // Add to opus queue
                    {
                        std::lock_guard<std::mutex> lock(self->wake_word_mutex_);
                        self->wake_word_opus_.push_back(std::move(opus_buffer));
                    }
                } else {
                    ESP_LOGE(TAG, "Opus encoding failed: %d", opus_len);
                }
            }

            // Add termination marker (empty vector)
            {
                std::lock_guard<std::mutex> lock(self->wake_word_mutex_);
                self->wake_word_opus_.push_back(std::vector<uint8_t>());
            }

            // Signal completion
            self->wake_word_cv_.notify_one();

            // Clean up
            opus_encoder_destroy(encoder);
            vTaskDelete(NULL);
        },
        "wake_word_encode",
        configMINIMAL_STACK_SIZE * 4,
        this,
        tskIDLE_PRIORITY + 1,
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (wake_word_encode_task_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create encode task");
    }
}

