#define TAG "atk_dnesp32s3"

class XL9555 : public I2cDevice
{
public:
    InitializeButtons() {
        i2c_config_t conf = {
            .mode = I2C_MODE_MASTER,
            .sda_io_num = CONFIG_I2C_SDA_PIN,  // Assuming these are defined in config.h
            .scl_io_num = CONFIG_I2C_SCL_PIN,
            .sda_pullup_en = GPIO_PULLUP_ENABLE,
            .scl_pullup_en = GPIO_PULLUP_ENABLE,
            .master.clk_speed = 100000,
        };

        esp_err_t ret = i2c_param_config(I2C_NUM_0, &conf);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to configure I2C parameters");
            return;
        }

        ret = i2c_driver_install(I2C_NUM_0, I2C_MODE_MASTER, 0, 0, 0);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to install I2C driver");
            return;
        }

        // Initialize XL9555 at address 0x20
        uint8_t addr = 0x20;
        uint8_t data[2] = {0x00, 0xFF}; // Configure all pins as inputs

        ret = i2c_master_write_to_device(I2C_NUM_0, addr, data, 2, 1000 / portTICK_PERIOD_MS);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to initialize XL9555");
        }
    }

    // Implementation of InitializeI2c() function
    void InitializeI2c() {
        i2c_config_t conf = {
            .mode = I2C_MODE_MASTER,
            .sda_io_num = CONFIG_I2C_SDA_PIN,
            .scl_io_num = CONFIG_I2C_SCL_PIN,
            .sda_pullup_en = GPIO_PULLUP_ENABLE,
            .scl_pullup_en = GPIO_PULLUP_ENABLE,
            .master.clk_speed = 100000,
        };

        esp_err_t ret = i2c_param_config(I2C_NUM_0, &conf);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to configure I2C parameters");
            return;
        }

        ret = i2c_driver_install(I2C_NUM_0, I2C_MODE_MASTER, 0, 0, 0);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to install I2C driver");
            return;
        }

        // Initialize XL9555 device at address 0x20
        // Configure all ports as inputs initially
        uint8_t xl9555_addr = 0x20;
        uint8_t config_data[2] = {0x06, 0xFF}; // Port configuration registers

        ret = i2c_master_write_to_device(I2C_NUM_0, xl9555_addr, config_data, 2, 1000 / portTICK_PERIOD_MS);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to initialize XL9555 device at address 0x20");
        } else {
            ESP_LOGI(TAG, "I2C initialized successfully with XL9555 at 0x20");
        }
    }
};

esp_err_t InitializeSpi() {
    esp_err_t ret = ESP_OK;

    // Configure SPI bus parameters
    spi_bus_config_t spi_bus_config = {
        .mosi_io_num = PIN_NUM_MOSI,
        .miso_io_num = PIN_NUM_MISO,
        .sclk_io_num = PIN_NUM_SCLK,
        .quadwp_io_num = -1,
        .quadhd_io_num = -1,
        .max_transfer_sz = 4094,
        .flags = SPICOMMON_BUSFLAG_MASTER,
        .intr_flags = 0
    };

    // Initialize SPI bus
    ret = spi_bus_initialize(SPI2_HOST, &spi_bus_config, SPI_DMA_CH_AUTO);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize SPI bus");
        return ret;
    }

    // Configure SPI device for LCD display
    spi_device_interface_config_t lcd_spi_config = {
        .mode = 0,
        .clock_speed_hz = 40000000,
        .duty_cycle_pos = 128,
        .cs_ena_pretrans = 0,
        .cs_ena_posttrans = 0,
        .queue_size = 1,
        .pre_cb = NULL,
        .post_cb = NULL,
        .spics_io_num = PIN_NUM_CS,
        .flags = 0,
        .command_bits = 0,
        .address_bits = 0,
        .dummy_bits = 0
    };

    // Add device to SPI bus
    spi_device_handle_t spi_device;
    ret = spi_bus_add_device(SPI2_HOST, &lcd_spi_config, &spi_device);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to add SPI device");
        return ret;
    }

    // Store the SPI handle for later use
    // Assuming there's a member variable to store this
    // lcd_spi_device = spi_device;

    ESP_LOGI(TAG, "SPI bus initialized successfully");
    return ESP_OK;
}

