InitializeButtons() {
    // Initialize I2C bus for the XL9555 GPIO expander
    i2c_config_t conf = {
        .mode = I2C_MODE_MASTER,
        .sda_io_num = GPIO_NUM_18,  // Assuming these GPIOs are defined elsewhere
        .scl_io_num = GPIO_NUM_19,
        .sda_pullup_en = GPIO_PULLUP_ENABLE,
        .scl_pullup_en = GPIO_PULLUP_ENABLE,
        .master = {
            .clk_speed = 100000,
        },
        .clk_flags = 0,
    };

    // Initialize I2C master
    esp_err_t err = i2c_bus_initialize(I2C_NUM_0, &conf);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize I2C bus for XL9555");
        return;
    }

    // Configure the XL9555 GPIO expander
    // Set button pin as input with pull-up
    uint8_t port_config = 0xFF;  // All pins as inputs (assuming button connects to GND when pressed)
    write_register(0x00, port_config);  // Configuration register for port 0

    // Enable internal pull-ups for button inputs
    uint8_t pullup_config = 0xFF;  // Enable pull-ups on all pins
    write_register(0x06, pullup_config);  // Pull-up register for port 0

    // Setup button callback for boot button
    Button* boot_button = new Button(GPIO_NUM_0);  // Assuming boot button is on GPIO 0
    boot_button->setClickHandler([]() {
        // Check current application state
        if (is_wifi_config_mode()) {
            // Enter normal operation mode
            enter_normal_operation();
        } else {
            // Toggle chat state in normal operation
            toggle_chat_state();
        }
    });

    // Setup long press handler for Wi-Fi configuration mode
    boot_button->setLongPressHandler([]() {
        // Enter Wi-Fi configuration mode
        enter_wifi_config_mode();
    });

    // Register the button with the application
    Application::getInstance()->registerButton(boot_button);
}

esp_err_t InitializeSt7789Display()
{
    esp_err_t ret = ESP_OK;

    // Configure SPI bus for display
    spi_bus_config_t spi_bus_cfg = {
        .mosi_io_num = BOARD_LCD_MOSI_PIN,
        .miso_io_num = BOARD_LCD_MISO_PIN,
        .sclk_io_num = BOARD_LCD_SCLK_PIN,
        .quadwp_io_num = -1,
        .quadhd_io_num = -1,
        .max_transfer_sz = 4 * 1024,
        .flags = SPICOMMON_BUSFLAG_MASTER,
        .intr_flags = 0
    };

    ret = spi_bus_initialize(BOARD_LCD_SPI_HOST, &spi_bus_cfg, SPI_DMA_CH_AUTO);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize SPI bus for display");
        return ret;
    }

    // Configure LCD panel
    esp_lcd_panel_dev_config_t panel_config = {
        .reset_gpio_num = BOARD_LCD_RST_PIN,
        .rgb_ele_order = LCD_RGB_ELEMENT_ORDER_RGB,
        .bits_per_pixel = 16,
    };

    // Initialize ST7789 panel
    esp_lcd_panel_handle_t panel_handle = NULL;
    ret = esp_lcd_new_panel_st7789(BOARD_LCD_SPI_HOST, &panel_config, &panel_handle);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize ST7789 panel");
        return ret;
    }

    // Initialize display with settings
    ret = esp_lcd_panel_reset(panel_handle);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to reset LCD panel");
        return ret;
    }

    // Set display orientation and other settings
    ret = esp_lcd_panel_disp_on_off(panel_handle, true);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to turn on display");
        return ret;
    }

    // Apply display settings
    ret = esp_lcd_panel_invert_color(panel_handle, true);  // Enable color inversion
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set color inversion");
        return ret;
    }

    // Swap axes (if needed for your specific display orientation)
    ret = esp_lcd_panel_swap_xy(panel_handle, false);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to swap axes");
        return ret;
    }

    // Mirror display if needed
    ret = esp_lcd_panel_mirror(panel_handle, false, false);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set mirror mode");
        return ret;
    }

    // Create display object for application use
    g_lcd_display = new LcdDisplay(panel_handle);
    if (!g_lcd_display) {
        ESP_LOGE(TAG, "Failed to create LCD display object");
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "ST7789 display initialized successfully");
    return ESP_OK;
}

