void InitializeCamera() {
    // Initialize camera power and reset through I2C expander
    // Assuming we have an XL9555 I2C expander for camera control

    // Configure DVP pin settings for camera interface
    static esp_cam_ctlr_dvp_pin_config_t dvp_pin_config = {
        .data_width = CAM_CTLR_DATA_WIDTH_8,
        .pclk = CAMERA_PCLK_PIN,
        .vsync = CAMERA_VSYNC_PIN,
        .href = CAMERA_HREF_PIN,
        .sda = CAMERA_SDA_PIN,
        .scl = CAMERA_SCL_PIN,
        .d0 = CAMERA_D0_PIN,
        .d1 = CAMERA_D1_PIN,
        .d2 = CAMERA_D2_PIN,
        .d3 = CAMERA_D3_PIN,
        .d4 = CAMERA_D4_PIN,
        .d5 = CAMERA_D5_PIN,
        .d6 = CAMERA_D6_PIN,
        .d7 = CAMERA_D7_PIN,
    };

    // Configure SCCB/I2C interface for camera communication
    esp_cam_ctlr_sccb_config_t sccb_config = {
        .port = CAMERA_SCCB_I2C_PORT,
        .sda_io_num = CAMERA_SDA_PIN,
        .scl_io_num = CAMERA_SCL_PIN,
        .sda_pullup_en = GPIO_PULLUP_ENABLE,
        .scl_pullup_en = GPIO_PULLUP_ENABLE,
        .clock_speed = 100000,
    };

    // Enable camera power first
    EnableCameraPower();

    // Add delay for power stabilization
    vTaskDelay(10 / portTICK_PERIOD_MS);

    // Reset camera
    ResetCamera();

    // Add delay for reset stabilization
    vTaskDelay(10 / portTICK_PERIOD_MS);

    // Initialize camera controller with configured pins
    esp_cam_ctlr_handle_t cam_ctlr_handle = NULL;
    esp_cam_ctlr_config_t cam_ctlr_config = {
        .type = ESP_CAM_CTLR_TYPE_DVP,
        .dvp = &dvp_pin_config,
        .sccb = &sccb_config,
    };

    esp_err_t ret = esp_cam_ctlr_new(&cam_ctlr_config, &cam_ctlr_handle);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create camera controller");
        return;
    }

    // Create and configure camera sensor
    esp_cam_sensor_config_t sensor_config = {
        .ctlr_handle = cam_ctlr_handle,
        .pin_pwdn = CAMERA_PWDN_PIN,
        .pin_reset = CAMERA_RESET_PIN,
        .pin_xclk = CAMERA_XCLK_PIN,
        .xclk_freq_hz = CAMERA_XCLK_FREQ,
        .ledc_channel = LEDC_CHANNEL_0,
        .ledc_timer = LEDC_TIMER_0,
        .pixel_format = PIXFORMAT_YUV422,
        .frame_size = FRAMESIZE_QVGA,
        .jpeg_quality = 10,
        .fb_count = 2,
    };

    esp_cam_sensor_handle_t sensor_handle = NULL;
    ret = esp_cam_sensor_new(&sensor_config, &sensor_handle);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create camera sensor");
        esp_cam_ctlr_del(cam_ctlr_handle);
        return;
    }

    // Store the sensor handle for later use
    camera_sensor_handle_ = sensor_handle;

    ESP_LOGI(TAG, "Camera initialized successfully");
}

