FrequencyDetector::FrequencyDetector(float frequency, size_t window_size) 
    : frequency_(frequency),
      window_size_(window_size) {

    // Calculate angular frequency: ω = 2πf
    angular_frequency_ = 2.0f * M_PI * frequency_;

    // Calculate cosine and sine coefficients
    cos_coefficient_ = cosf(angular_frequency_);
    sin_coefficient_ = sinf(angular_frequency_);

    // Calculate filter coefficient: 2 * cos(ω)
    filter_coefficient_ = 2.0f * cos_coefficient_;

    // Calculate frequency bin (this is typically just the normalized frequency)
    frequency_bin_ = frequency_;

    // Initialize state buffer with zeros (size 2 for S[-1] and S[-2])
    state_buffer_.assign(2, 0.0f);
}

