float FrequencyDetector::GetAmplitude() const {
    // If there are fewer than 2 samples in the buffer, return zero
    if (state_buffer_.size() < 2) {
        return 0.0f;
    }

    // Get the last two samples from the state buffer
    // The state buffer stores S[-1] and S[-2] in order
    float s_minus_1 = state_buffer_[state_buffer_.size() - 1];  // S[-1]
    float s_minus_2 = state_buffer_[state_buffer_.size() - 2];  // S[-2]

    // Apply Goertzel algorithm to compute real and imaginary parts
    // Based on the algorithm: 
    // real = s_n * cos_coefficient_ - s_n_minus_1 * sin_coefficient_
    // imaginary = s_n * sin_coefficient_ + s_n_minus_1 * cos_coefficient_
    float real = s_minus_1 * cos_coefficient_ - s_minus_2 * sin_coefficient_;
    float imaginary = s_minus_1 * sin_coefficient_ + s_minus_2 * cos_coefficient_;

    // Calculate amplitude as sqrt(real^2 + imaginary^2)
    float amplitude = sqrtf(real * real + imaginary * imaginary);

    // Normalize by half the window size as specified in requirements
    amplitude /= (window_size_ / 2.0f);

    return amplitude;
}

