            // Calculate probability of mark tone presence
            // If both amplitudes are zero, return 0.0
            if (mark_amplitude == 0.0f && space_amplitude == 0.0f) {
                mark_probabilities.push_back(0.0f);
            } else {
                // Probability is the ratio of mark amplitude to total amplitude
                float total_amplitude = mark_amplitude + space_amplitude;
                mark_probabilities.push_back(mark_amplitude / total_amplitude);
            }

            // Remove the processed samples from buffer
            input_buffer_.pop_front();
        }
    }

    return mark_probabilities;
}

