bool AudioDataBuffer::ProcessProbabilityData(const std::vector<float> &probabilities, float threshold) {
    // Process each probability value
    for (float prob : probabilities) {
        // Convert probability to bit (1 if > threshold, 0 otherwise)
        uint8_t bit = (prob > threshold) ? 1 : 0;

        // Add bit to our bit buffer
        bit_buffer_.push_back(bit);

        // Add bit to identifier buffer for pattern matching
        identifier_buffer_.push_back(bit);

        // Keep identifier buffer at maximum size
        if (identifier_buffer_.size() > identifier_buffer_size_) {
            identifier_buffer_.pop_front();
        }

        // Check if we're in waiting state and have enough bits to check for start identifier
        if (current_state_ == DataReceptionState::kWaiting) {
            // Check if we've matched the start identifier
            if (identifier_buffer_.size() >= start_of_transmission_.size()) {
                bool match = true;
                for (size_t i = 0; i < start_of_transmission_.size(); ++i) {
                    if (identifier_buffer_[identifier_buffer_.size() - start_of_transmission_.size() + i] != 
                        start_of_transmission_[i]) {
                        match = false;
                        break;
                    }
                }

                if (match) {
                    // Found start identifier, transition to receiving state
                    current_state_ = DataReceptionState::kReceiving;
                    // Clear the bit buffer except for the start identifier bits
                    bit_buffer_.clear();
                    // Add back the start identifier bits to the buffer
                    for (size_t i = 0; i < start_of_transmission_.size(); ++i) {
                        bit_buffer_.push_back(start_of_transmission_[i]);
                    }
                }
            }
        }
        // Check if we're in receiving state
        else if (current_state_ == DataReceptionState::kReceiving) {
            // Check if we've reached maximum buffer size
            if (bit_buffer_.size() >= max_bit_buffer_size_) {
                // Try to decode the data
                auto bytes = ConvertBitsToBytes(bit_buffer_);

                // Convert to string
                std::string text(bytes.begin(), bytes.end());

                // Check if this is the end identifier
                if (text.length() >= end_of_transmission_.size()) {
                    bool end_match = true;
                    for (size_t i = 0; i < end_of_transmission_.size(); ++i) {
                        if (text[text.length() - end_of_transmission_.size() + i] != 
                            end_of_transmission_[i]) {
                            end_match = false;
                            break;
                        }
                    }

                    if (end_match) {
                        // Found end identifier, process the data
                        // Remove the end identifier from the data
                        std::string data_text = text.substr(0, text.length() - end_of_transmission_.size());

                        // If checksum validation is enabled, verify it
                        if (enable_checksum_validation_) {
                            // Extract the checksum part (assuming it's at the end)
                            if (data_text.length() >= 1) {
                                uint8_t calculated_checksum = CalculateChecksum(data_text.substr(0, data_text.length() - 1));
                                uint8_t received_checksum = static_cast<uint8_t>(data_text.back());

                                if (calculated_checksum == received_checksum) {
                                    decoded_text = data_text.substr(0, data_text.length() - 1);
                                    ClearBuffers();
                                    return true;
                                } else {
                                    // Checksum mismatch, clear buffers and return false
                                    ClearBuffers();
                                    return false;
                                }
                            }
                        } else {
                            // No checksum validation, just return the data
                            decoded_text = data_text;
                            ClearBuffers();
                            return true;
                        }
                    }
                }
            }
        }
        // Check if we're in inactive state and look for start identifier
        else if (current_state_ == DataReceptionState::kInactive) {
            // Look for start identifier
            if (identifier_buffer_.size() >= start_of_transmission_.size()) {
                bool match = true;
                for (size_t i = 0; i < start_of_transmission_.size(); ++i) {
                    if (identifier_buffer_[identifier_buffer_.size() - start_of_transmission_.size() + i] != 
                        start_of_transmission_[i]) {
                        match = false;
                        break;
                    }
                }

                if (match) {
                    // Found start identifier, transition to waiting state
                    current_state_ = DataReceptionState::kWaiting;
                    // Clear the bit buffer
                    bit_buffer_.clear();
                    // Add the start identifier bits to the buffer
                    for (size_t i = 0; i < start_of_transmission_.size(); ++i) {
