void Backlight::OnTransitionTimer()
{
    // Check if we've reached the target brightness
    if (brightness_ == target_brightness_) {
        // Stop the transition timer
        if (transition_timer_ != nullptr) {
            esp_timer_stop(transition_timer_);
            esp_timer_delete(transition_timer_);
            transition_timer_ = nullptr;
        }
        return;
    }

    // Determine direction of change
    if (brightness_ < target_brightness_) {
        // Increasing brightness
        if (brightness_ + step_ <= target_brightness_) {
            brightness_ += step_;
        } else {
            brightness_ = target_brightness_;
        }
    } else {
        // Decreasing brightness
        if (brightness_ >= step_ && brightness_ - step_ >= target_brightness_) {
            brightness_ -= step_;
        } else {
            brightness_ = target_brightness_;
        }
    }

    // Update the actual brightness via hardware
    SetBrightnessImpl(brightness_);

    // If we've reached the target, stop the timer
    if (brightness_ == target_brightness_) {
        if (transition_timer_ != nullptr) {
            esp_timer_stop(transition_timer_);
            esp_timer_delete(transition_timer_);
            transition_timer_ = nullptr;
        }
    }
}

