void PwmBacklight::SetBrightnessImpl(uint8_t brightness) {
    // Map brightness percentage (0-100) to 10-bit PWM value (0-1023)
    uint32_t pwm_duty = (brightness * 1023) / 100;

    // Configure LEDC channel with new duty cycle
    esp_err_t result = ledc_set_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, pwm_duty);
    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set LEDC duty cycle: %d", result);
        return;
    }

    // Update the LEDC channel
    result = ledc_update_duty(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0);
    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to update LEDC duty cycle: %d", result);
        return;
    }
}

