Board::Board() {
    esp_err_t err;

    // Initialize NVS if not already done
    err = nvs_flash_init();
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize NVS: %s", esp_err_to_name(err));
        return;
    }

    // Open NVS namespace for board settings
    nvs_handle_t nvs_handle;
    err = nvs_open("board", NVS_READWRITE, &nvs_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open NVS: %s", esp_err_to_name(err));
        return;
    }

    // Try to get existing UUID from NVS
    size_t uuid_size = 0;
    err = nvs_get_str(nvs_handle, "uuid", nullptr, &uuid_size);

    if (err == ESP_OK && uuid_size > 0) {
        // UUID exists, retrieve it
        char* uuid_buffer = new char[uuid_size];
        err = nvs_get_str(nvs_handle, "uuid", uuid_buffer, &uuid_size);
        if (err == ESP_OK) {
            uuid_ = std::string(uuid_buffer);
        } else {
            ESP_LOGW(TAG, "Failed to read UUID from NVS: %s", esp_err_to_name(err));
            uuid_ = GenerateUuid();
        }
        delete[] uuid_buffer;
    } else {
        // UUID doesn't exist, generate new one and save it
        uuid_ = GenerateUuid();
        err = nvs_set_str(nvs_handle, "uuid", uuid_.c_str());
        if (err != ESP_OK) {
            ESP_LOGW(TAG, "Failed to save UUID to NVS: %s", esp_err_to_name(err));
        }
    }

    // Close NVS handle
    nvs_close(nvs_handle);
}

