#include <iomanip>
#include <sstream>
#include <string>

std::string Board::GenerateUuid() {
    // Generate 16 random bytes
    uint8_t uuid_bytes[16];
    for (int i = 0; i < 16; i += 4) {
        uint32_t random_val = esp_random();
        uuid_bytes[i] = (random_val >> 24) & 0xFF;
        uuid_bytes[i+1] = (random_val >> 16) & 0xFF;
        uuid_bytes[i+2] = (random_val >> 8) & 0xFF;
        uuid_bytes[i+3] = random_val & 0xFF;
    }

    // Set UUID version (4) in the 7th byte
    uuid_bytes[6] = (uuid_bytes[6] & 0x0F) | 0x40;

    // Set UUID variant (RFC 4122) in the 9th byte
    uuid_bytes[8] = (uuid_bytes[8] & 0x3F) | 0x80;

    // Format as UUID string
    std::stringstream ss;
    for (int i = 0; i < 16; i++) {
        ss << std::hex << std::setfill('0') << std::uppercase 
           << std::setw(2) << static_cast<int>(uuid_bytes[i]);

        // Add hyphens at appropriate positions
        if (i == 3 || i == 5 || i == 7 || i == 9) {
            ss << '-';
        }
    }

    return ss.str();
}

