Button::Button(gpio_num_t gpio_num, bool active_high, uint16_t long_press_time, uint16_t short_press_time, bool enable_power_save) 
    : gpio_num_(gpio_num) {

    if (gpio_num == GPIO_NUM_NC) {
        button_handle_ = nullptr;
        return;
    }

    button_config_t btn_config = {
        .type = BUTTON_TYPE_GPIO,
        .gpio_button_config = {
            .gpio_num = gpio_num,
            .active_level = active_high ? 1 : 0,
        },
    };

    button_handle_ = iot_button_create(&btn_config);

    if (button_handle_ != nullptr) {
        // Configure press times if they are non-zero
        if (long_press_time > 0) {
            iot_button_set_long_press_time(button_handle_, long_press_time);
        }
        if (short_press_time > 0) {
            iot_button_set_short_press_time(button_handle_, short_press_time);
        }

        // Enable power save mode if requested
        if (enable_power_save) {
            iot_button_enable_power_save(button_handle_);
        }
    }
}

