void Button::OnClick(std::function<void()> callback) {
    if (button_handle_ == nullptr) {
        return;
    }

    on_click_ = callback;

    // Register the callback with the IoT button library
    iot_button_register_cb(button_handle_, BUTTON_CB_CLICK, [](void* arg) {
        Button* button = static_cast<Button*>(arg);
        if (button->on_click_) {
            button->on_click_();
        }
    }, this);
}

