I2cDevice::I2cDevice(i2c_master_bus_handle_t i2c_bus, uint8_t addr)
{
    // Configure the I2C device with standard settings
    i2c_device_config_t dev_config = {
        .dev_addr_length = I2C_ADDR_BIT_LEN_7,
        .device_address = addr,
        .scl_speed_hz = 100000,  // Standard I2C speed
    };

    // Register the device with the I2C master bus
    esp_err_t ret = i2c_master_bus_register_device(i2c_bus, &dev_config, &i2c_device_);

    // Check if registration was successful
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to register I2C device: %s", esp_err_to_name(ret));
        assert(0 && "Failed to register I2C device");
    }

    // Verify that the device handle is valid
    assert(i2c_device_ != NULL && "I2C device handle is invalid");
}

