uint8_t I2cDevice::ReadReg(uint8_t reg) {
    uint8_t value;

    // Create I2C command link
    i2c_cmd_handle_t cmd = i2c_cmd_link_create();

    // Start condition
    i2c_master_start(cmd);

    // Send device address with write bit
    i2c_master_write_byte(cmd, (i2c_device_->dev_addr << 1) | I2C_MASTER_WRITE, true);

    // Send register address
    i2c_master_write_byte(cmd, reg, true);

    // Re-start condition
    i2c_master_start(cmd);

    // Send device address with read bit
    i2c_master_write_byte(cmd, (i2c_device_->dev_addr << 1) | I2C_MASTER_READ, true);

    // Read single byte
    i2c_master_read_byte(cmd, &value, I2C_MASTER_LAST_NACK);

    // Stop condition
    i2c_master_stop(cmd);

    // Execute command
    esp_err_t err = i2c_master_cmd_begin(i2c_device_->bus, cmd, 1000 / portTICK_PERIOD_MS);

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read from I2C device at address 0x%02X, register 0x%02X: %s", 
                 i2c_device_->dev_addr, reg, esp_err_to_name(err));
        value = 0; // Return default value on error
    }

    // Clean up command link
    i2c_cmd_link_delete(cmd);

    return value;
}

