void WifiBoard::StartNetwork() {
    // Initialize WiFi manager with predefined SSID prefix and language
    wifi_manager::Initialize(CONFIG_WIFI_SSID_PREFIX, LANG_ENGLISH);

    // Set up unified event callback to handle various WiFi events
    wifi_manager::SetEventCallback([this](wifi_manager_event_t event, const std::string& data) {
        switch (event) {
            case WIFI_MANAGER_EVENT_SCANNING:
                ESP_LOGI(TAG, "WiFi scanning started");
                OnNetworkEvent(NetworkEvent::SCANNING);
                break;
            case WIFI_MANAGER_EVENT_CONNECTING:
                ESP_LOGI(TAG, "Connecting to WiFi network: %s", data.c_str());
                OnNetworkEvent(NetworkEvent::CONNECTING, data);
                // Start connection timeout timer
                if (connect_timer_ == nullptr) {
                    esp_timer_create_args_t timer_args = {
                        .callback = OnWifiConnectTimeout,
                        .arg = this,
                        .name = "wifi_connect_timeout"
                    };
                    esp_timer_create(&timer_args, &connect_timer_);
                }
                esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);
                break;
            case WIFI_MANAGER_EVENT_CONNECTED:
                ESP_LOGI(TAG, "WiFi connected to network: %s", data.c_str());
                if (connect_timer_ != nullptr) {
                    esp_timer_stop(connect_timer_);
                }
                OnNetworkEvent(NetworkEvent::CONNECTED, data);
                break;
            case WIFI_MANAGER_EVENT_DISCONNECTED:
                ESP_LOGI(TAG, "WiFi disconnected");
                if (connect_timer_ != nullptr) {
                    esp_timer_stop(connect_timer_);
                }
                OnNetworkEvent(NetworkEvent::DISCONNECTED);
                // Try to reconnect
                TryWifiConnect();
                break;
            case WIFI_MANAGER_EVENT_CONFIG_MODE_ENTER:
                ESP_LOGI(TAG, "Entering WiFi configuration mode");
                in_config_mode_ = true;
                OnNetworkEvent(NetworkEvent::CONFIG_MODE_ENTER);
                break;
            case WIFI_MANAGER_EVENT_CONFIG_MODE_EXIT:
                ESP_LOGI(TAG, "Exiting WiFi configuration mode");
                in_config_mode_ = false;
                OnNetworkEvent(NetworkEvent::CONFIG_MODE_EXIT);
                break;
            default:
                ESP_LOGW(TAG, "Unknown WiFi event: %d", event);
                break;
        }
    });

    // Attempt to establish WiFi connection
    TryWifiConnect();
}

