void WifiBoard::TryWifiConnect() {
    ESP_LOGI(TAG, "Attempting to connect to WiFi...");

    // Check if there are any configured SSIDs
    if (!SsidManager::HasConfiguredSsids()) {
        ESP_LOGW(TAG, "No SSIDs configured, starting WiFi configuration mode");

        // Brief delay before entering configuration mode
        vTaskDelay(1000 / portTICK_PERIOD_MS);

        // Start WiFi configuration mode
        WifiManager::StartConfigurationMode();
        return;
    }

    // Attempt to connect to available networks
    bool connected = false;
    int attempt = 0;
    const int max_attempts = 3;

    while (!connected && attempt < max_attempts) {
        ESP_LOGI(TAG, "WiFi connection attempt %d/%d", attempt + 1, max_attempts);

        // Try to connect with timeout
        connected = WifiStation::Connect(CONNECT_TIMEOUT_SEC);

        if (!connected) {
            ESP_LOGW(TAG, "Failed to connect, retrying...");
            attempt++;

            if (attempt < max_attempts) {
                // Wait before retrying
                vTaskDelay(2000 / portTICK_PERIOD_MS);
            }
        }
    }

    if (connected) {
        ESP_LOGI(TAG, "Successfully connected to WiFi");

        // Update display with connection status
        auto disp = Board::GetInstance().GetDisplay();
        if (disp) {
            disp->Clear();
            disp->DrawString(0, 0, "WiFi Connected", FONT_SMALL);
            disp->DrawString(0, 20, WifiStation::GetConnectedSsid().c_str(), FONT_SMALL);
            disp->Update();
        }
    } else {
        ESP_LOGW(TAG, "Failed to connect after %d attempts, starting configuration mode", max_attempts);

        // Brief delay before entering configuration mode
        vTaskDelay(1000 / portTICK_PERIOD_MS);

        // Start WiFi configuration mode
        WifiManager::StartConfigurationMode();
    }
}

