void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string& data) {
    ESP_LOGD(TAG, "Network event: %d, data: %s", static_cast<int>(event), data.c_str());

    // Handle different network events
    switch (event) {
        case NetworkEvent::Connecting: {
            // Start connection timer
            if (connect_timer_ != nullptr) {
                esp_timer_stop(connect_timer_);
                esp_timer_delete(connect_timer_);
                connect_timer_ = nullptr;
            }

            esp_timer_create_args_t timer_args = {
                .callback = &OnWifiConnectTimeout,
                .arg = this,
                .name = "wifi_connect"
            };

            esp_timer_create(&timer_args, &connect_timer_);
            esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);

            // Update UI or display status
            if (data.empty()) {
                // Show connecting state without specific SSID
                // Implementation would depend on display system
            } else {
                // Show connecting to specific SSID
                // Implementation would depend on display system
            }
            break;
        }

        case NetworkEvent::Connected: {
            // Stop connection timer
            if (connect_timer_ != nullptr) {
                esp_timer_stop(connect_timer_);
                esp_timer_delete(connect_timer_);
                connect_timer_ = nullptr;
            }

            // Release provisioning resources if we were in config mode
            if (in_config_mode_) {
                in_config_mode_ = false;
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
                // Stop BLUFI provisioning if active
                blufi_deinit();
#endif
            }

            // Notify external callback
            if (network_event_callback_) {
                network_event_callback_(event, data);
            }
            break;
        }

        case NetworkEvent::Disconnected: {
            // Stop connection timer
            if (connect_timer_ != nullptr) {
                esp_timer_stop(connect_timer_);
                esp_timer_delete(connect_timer_);
                connect_timer_ = nullptr;
            }

            // If we were in configuration mode, try to reconnect
            if (in_config_mode_) {
                // Trigger reconnection attempt
                TryWifiConnect();
            }

            // Notify external callback
            if (network_event_callback_) {
                network_event_callback_(event, data);
            }
            break;
        }

        case NetworkEvent::ConfigModeStarted: {
            in_config_mode_ = true;

            // Stop any ongoing connection attempts
            if (connect_timer_ != nullptr) {
                esp_timer_stop(connect_timer_);
                esp_timer_delete(connect_timer_);
                connect_timer_ = nullptr;
            }

            // Notify external callback
            if (network_event_callback_) {
                network_event_callback_(event, data);
            }
            break;
        }

        case NetworkEvent::ConfigModeEnded: {
            in_config_mode_ = false;

            // Trigger reconnection attempt
            TryWifiConnect();

            // Notify external callback
            if (network_event_callback_) {
                network_event_callback_(event, data);
            }
            break;
        }

        default: {
            // For other events, just notify the callback
            if (network_event_callback_) {
                network_event_callback_(event, data);
            }
            break;
        }
    }
}

