void WifiBoard::OnWifiConnectTimeout(void* arg) {
    ESP_LOGI(TAG, "WiFi connection timeout occurred");

    WifiBoard* board = static_cast<WifiBoard*>(arg);
    if (board == nullptr) {
        ESP_LOGE(TAG, "Invalid WifiBoard pointer in timeout callback");
        return;
    }

    // Stop the current WiFi station mode
    wifi_station_stop();

    // Enter configuration mode to allow user to reconfigure network settings
    board->StartWifiConfigMode();
}

