void WifiBoard::StartWifiConfigMode() {
    ESP_LOGI(TAG, "Starting WiFi configuration mode");

    // Set device state to configuring mode
    in_config_mode_ = true;

    // Get display for user feedback
    auto disp = Board::GetInstance().GetDisplay();

    // Show configuration mode indicator on display
    if (disp) {
        disp->Clear();
        disp->DrawString(0, 0, "WiFi Config Mode", FONT_MEDIUM);
        disp->DrawString(0, 20, "Press button to connect", FONT_SMALL);
        disp->Update();
    }

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Start BLE provisioning if enabled
    ESP_LOGI(TAG, "Starting BLUFI provisioning");
    blufi_start_provisioning();
#elif defined(CONFIG_USE_WIFI_HOTSPOT_CONFIG)
    // Start hotspot-based configuration
    ESP_LOGI(TAG, "Starting hotspot configuration");
    wifi_manager_start_hotspot();
#elif defined(CONFIG_USE_AUDIO_WIFI_PROVISIONING)
    // Start audio-based provisioning
    ESP_LOGI(TAG, "Starting audio provisioning");
    // Create a task to handle audio provisioning
    xTaskCreate([](void* arg) {
        auto board = static_cast<WifiBoard*>(arg);
        auto disp = Board::GetInstance().GetDisplay();

        // Initialize audio wifi config
        audio_wifi_config::ReceiveWifiCredentialsFromAudio(
            &Application::GetInstance(), 
            &board->wifi_, 
            disp, 
            0 // channel parameter
        );

        vTaskDelete(NULL);
    }, "audio_config_task", 4096, this, 5, NULL);
#endif

    // Start connection timeout timer
    if (connect_timer_ == nullptr) {
        const esp_timer_create_args_t timer_args = {
            .callback = OnWifiConnectTimeout,
            .arg = this,
            .name = "wifi_connect_timeout"
        };
        esp_timer_create(&timer_args, &connect_timer_);
    }

    // Reset and start the timeout timer
    esp_timer_stop(connect_timer_);
    esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);
}

