void WifiBoard::EnterWifiConfigMode() {
    // Check if we're already in config mode to prevent conflicts
    if (in_config_mode_) {
        ESP_LOGW(TAG, "Already in WiFi config mode");
        return;
    }

    // Display notification about entering config mode
    auto disp = Board::GetInstance().GetDisplay();
    if (disp) {
        disp->Clear();
        disp->DrawText(0, 0, "WiFi Config Mode", 1);
        disp->DrawText(0, 20, "Press button to connect", 1);
        disp->Update();
    }

    // Stop any active audio/communication processes
    // This would typically involve stopping audio tasks, disabling radio, etc.
    // Based on the includes, we might need to stop AFSK demodulation
    afsk_demod::Stop();

    // Reset network connection state
    // Cancel any pending connection attempts
    if (connect_timer_ != nullptr) {
        esp_timer_stop(connect_timer_);
        esp_timer_delete(connect_timer_);
        connect_timer_ = nullptr;
    }

    // Set the flag indicating we're in config mode
    in_config_mode_ = true;

    // Start the actual WiFi configuration mode
    StartWifiConfigMode();
}

