const char* WifiBoard::GetNetworkStateIcon() {
    // Check if in configuration mode
    if (in_config_mode_) {
        return FONT_AWESOME_WIFI_CONFIGURATION;
    }

    // Get WiFi station instance
    auto wifi_station = WifiStation::GetInstance();
    if (wifi_station == nullptr) {
        return FONT_AWESOME_SIGNAL_OFF;
    }

    // Check if connected
    if (!wifi_station->IsConnected()) {
        return FONT_AWESOME_SIGNAL_OFF;
    }

    // Get signal strength
    int rssi = wifi_station->GetRssi();
    if (rssi == 0) {
        return FONT_AWESOME_SIGNAL_OFF;
    } else if (rssi < -80) {
        return FONT_AWESOME_SIGNAL_WEAK;
    } else if (rssi < -67) {
        return FONT_AWESOME_SIGNAL_FAIR;
    } else if (rssi < -50) {
        return FONT_AWESOME_SIGNAL_GOOD;
    } else {
        return FONT_AWESOME_SIGNAL_STRONG;
    }
}

