std::string WifiBoard::GetBoardJson() {
    cJSON* root = cJSON_CreateObject();
    if (!root) {
        return "";
    }

    // Add board type
    cJSON_AddStringToObject(root, "type", GetBoardType().c_str());

    // Add board name (using UUID as name)
    cJSON_AddStringToObject(root, "name", GetUuid().c_str());

    // Add MAC address
    cJSON_AddStringToObject(root, "mac", SystemInfo::GetMacAddress().c_str());

    // Add Wi-Fi information only when not in configuration mode
    if (!in_config_mode_) {
        // Get current Wi-Fi station information
        auto wifi_station = wifi_manager_get_station();
        if (wifi_station) {
            // Add SSID if connected
            std::string ssid = wifi_station->get_ssid();
            if (!ssid.empty()) {
                cJSON_AddStringToObject(root, "ssid", ssid.c_str());
            }

            // Add RSSI if available
            int rssi = wifi_station->get_rssi();
            if (rssi != 0) {
                cJSON_AddNumberToObject(root, "rssi", rssi);
            }

            // Add channel if available
            int channel = wifi_station->get_channel();
            if (channel > 0) {
                cJSON_AddNumberToObject(root, "channel", channel);
            }

            // Add IP address if available
            std::string ip = wifi_station->get_ip();
            if (!ip.empty()) {
                cJSON_AddStringToObject(root, "ip", ip.c_str());
            }
        }
    }

    // Convert to string
    char* str = cJSON_PrintUnformatted(root);
    std::string result(str);
    cJSON_free(str);
    cJSON_Delete(root);

    return result;
}

