std::string WifiBoard::GetDeviceStatusJson() {
    cJSON *root = cJSON_CreateObject();
    if (!root) {
        return "";
    }

    // Add MAC address
    cJSON_AddStringToObject(root, "mac", SystemInfo::GetMacAddress().c_str());

    // Add battery info
    int battery_level = 0;
    bool charging = false;
    bool discharging = false;
    if (Board::GetInstance().GetBatteryLevel(battery_level, charging, discharging)) {
        cJSON_AddNumberToObject(root, "battery_level", battery_level);
        cJSON_AddBoolToObject(root, "charging", charging);
        cJSON_AddBoolToObject(root, "discharging", discharging);
    }

    // Add temperature
    float temperature = 0.0f;
    if (Board::GetInstance().GetTemperature(temperature)) {
        cJSON_AddNumberToObject(root, "temperature", temperature);
    }

    // Add display info (brightness and theme)
    Display* display = Board::GetInstance().GetDisplay();
    if (display) {
        cJSON_AddNumberToObject(root, "brightness", display->GetBrightness());

        // Theme information (assuming there's a way to get theme)
        // This might need to be adjusted based on actual implementation
        cJSON_AddStringToObject(root, "theme", "default"); // placeholder
    }

    // Add audio info (volume)
    // Assuming there's an audio component or method to get volume
    // This would typically come from audio subsystem
    cJSON_AddNumberToObject(root, "audio_volume", 50); // placeholder value

    // Add WiFi info
    WifiManager* wifi_manager = WifiManager::GetInstance();
    if (wifi_manager) {
        // Get current WiFi status
        WifiStation* station = wifi_manager->GetStation();
        if (station) {
            // Add SSID
            std::string ssid = station->GetSsid();
            if (!ssid.empty()) {
                cJSON_AddStringToObject(root, "ssid", ssid.c_str());

                // Add signal strength
                int rssi = station->GetRssi();
                cJSON_AddNumberToObject(root, "rssi", rssi);
            }
        }
    }

    // Add network state icon
    const char* icon = Board::GetInstance().GetNetworkStateIcon();
    if (icon) {
        cJSON_AddStringToObject(root, "network_icon", icon);
    }

    // Add board type
    cJSON_AddStringToObject(root, "board_type", Board::GetInstance().GetBoardType().c_str());

    // Add UUID
    cJSON_AddStringToObject(root, "uuid", Board::GetInstance().GetUuid().c_str());

    // Convert to string
    char* str = cJSON_PrintUnformatted(root);
    std::string result(str);
    cJSON_free(str);
    cJSON_Delete(root);

    return result;
}

