SingleLed::SingleLed(gpio_num_t gpio)
{
    // Configure RMT settings for WS2812
    led_strip_rmt_config_t rmt_config = {};
    rmt_config.resolution_hz = 10 * 1000 * 1000; // 10MHz resolution

    // Configure LED strip settings
    led_strip_config_t strip_config = {};
    strip_config.strip_gpio_num = gpio;
    strip_config.max_leds = 1; // Single LED
    strip_config.led_pixel_format = LED_PIXEL_FORMAT_GRB;
    strip_config.led_model = LED_MODEL_WS2812;

    // Create LED strip using RMT peripheral
    esp_err_t ret = led_strip_new_rmt_device(&strip_config, &rmt_config, &led_strip_);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create LED strip: %s", esp_err_to_name(ret));
        return;
    }

    // Clear the LED initially (turn off)
    led_strip_clear(led_strip_);

    // Set initial color values
    r_ = 0;
    g_ = 0;
    b_ = 0;

    // Initialize blink parameters
    blink_counter_ = 0;
    blink_interval_ms_ = 0;
    blink_timer_ = nullptr;
}

