    std::lock_guard<std::mutex> lock(mutex_);

    // Stop any ongoing blink timer
    if (blink_timer_ != nullptr) {
        esp_timer_stop(blink_timer_);
        esp_timer_delete(blink_timer_);
        blink_timer_ = nullptr;
    }

    // Stop any ongoing blink task
    if (blink_task_ != nullptr) {
        vTaskDelete(blink_task_);
        blink_task_ = nullptr;
    }

    // Set the LED color to configured RGB values
    led_strip_set_pixel(led_strip_, 0, r_, g_, b_);

    // Immediately refresh the LED strip to display the change
    led_strip_refresh(led_strip_);
}

