void SingleLed::TurnOff() {
    std::lock_guard<std::mutex> lock(mutex_);

    // Stop any active blinking timer
    if (blink_timer_) {
        esp_timer_stop(blink_timer_);
    }

    // Clear the LED strip state if initialized
    if (led_strip_) {
        // Set all LEDs to off (0 brightness)
        led_strip_clear(led_strip_);
    }
}

