void SingleLed::StartBlinkTask(int times, int interval_ms) {
    // Check if LED strip is initialized
    if (led_strip_ == nullptr) {
        ESP_LOGW(TAG, "LED strip not initialized, cannot start blink task");
        return;
    }

    // Store the blink parameters
    blink_counter_ = times;
    blink_interval_ms_ = interval_ms;

    // Create timer arguments
    esp_timer_create_args_t timer_args = {
        .callback = [](void* arg) {
            SingleLed* led = static_cast<SingleLed*>(arg);
            led->OnBlinkTimer();
        },
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK,
        .name = "led_blink_timer"
    };

    // Delete existing timer if it exists
    if (blink_timer_ != nullptr) {
        esp_timer_stop(blink_timer_);
        esp_timer_delete(blink_timer_);
        blink_timer_ = nullptr;
    }

    // Create new timer
    esp_err_t err = esp_timer_create(&timer_args, &blink_timer_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create blink timer: %s", esp_err_to_name(err));
        return;
    }

    // Start the timer with the specified interval
    err = esp_timer_start_periodic(blink_timer_, interval_ms * 1000); // Convert ms to us
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start blink timer: %s", esp_err_to_name(err));
        esp_timer_delete(blink_timer_);
        blink_timer_ = nullptr;
        return;
    }

    ESP_LOGD(TAG, "Started blink task with %d blinks every %d ms", times, interval_ms);
}

