        blink_counter_--;

        // Check if we should stop blinking
        if (blink_counter_ == 0) {
            // Stop the timer
            if (blink_timer_) {
                esp_timer_stop(blink_timer_);
                esp_timer_delete(blink_timer_);
                blink_timer_ = nullptr;
