MqttProtocol::~MqttProtocol() {
    // Stop and delete the reconnect timer
    if (reconnect_timer_) {
        esp_timer_stop(reconnect_timer_);
        esp_timer_delete(reconnect_timer_);
        reconnect_timer_ = nullptr;
    }

    // Reset MQTT resources
    if (mqtt_) {
        mqtt_.reset();
    }

    // Reset UDP resources
    if (udp_) {
        udp_.reset();
    }

    // Release the event group
    if (event_group_handle_) {
        vEventGroupDelete(event_group_handle_);
        event_group_handle_ = nullptr;
    }

    // Mark the instance as inactive to prevent pending tasks from executing
    if (alive_) {
        alive_->store(false);
    }
}

