bool MqttProtocol::StartMqttClient(bool report_error) {
    ESP_LOGI(TAG, "Starting MQTT client");

    // Get network configuration
    auto network = Board::GetInstance().GetNetwork();

    // Create MQTT client instance if not already created
    if (!mqtt_) {
        mqtt_ = std::make_unique<Mqtt>();
    }

    // Configure MQTT client
    MqttConfig config;
    config.broker_url = network.mqtt_broker.c_str();
    config.client_id = network.device_id.c_str();
    config.username = network.mqtt_username.c_str();
    config.password = network.mqtt_password.c_str();
    config.keepalive = MQTT_PING_INTERVAL_SECONDS;

    // Set up connection callback
    mqtt_->SetOnConnected([this](const char* client_id) {
        ESP_LOGI(TAG, "MQTT connected successfully");
        // Clear any previous reconnect timer
        if (reconnect_timer_) {
            esp_timer_stop(reconnect_timer_);
        }

        // Notify that we're connected
        xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);

        // Send hello message to server
        std::string hello_msg = GetHelloMessage();
        SendText(hello_msg);
    });

    // Set up disconnection callback
    mqtt_->SetOnDisconnected([this, report_error](const char* client_id, int error_code) {
        ESP_LOGW(TAG, "MQTT disconnected, error code: %d", error_code);

        // Report error if requested
        if (report_error) {
            // TODO: Implement error reporting mechanism
            ESP_LOGE(TAG, "MQTT connection lost with error: %d", error_code);
        }

        // Schedule reconnect attempt
        if (reconnect_timer_) {
            esp_timer_stop(reconnect_timer_);
        }

        // Start reconnect timer
        esp_timer_start_once(reconnect_timer_, MQTT_RECONNECT_INTERVAL_MS * 1000);
    });

    // Set up message receive callback with JSON parsing
    mqtt_->SetOnMessage([this](const char* topic, const uint8_t* payload, size_t len) {
        ESP_LOGD(TAG, "Received MQTT message on topic: %s", topic);

        // Parse JSON payload
        cJSON* root = cJSON_Parse((const char*)payload);
        if (root == NULL) {
            ESP_LOGE(TAG, "Failed to parse JSON message");
            return;
        }

        // Process different types of messages
        const char* msg_type = cJSON_GetObjectItem(root, "type") ? 
                              cJSON_GetObjectItem(root, "type")->valuestring : nullptr;

        if (msg_type && strcmp(msg_type, "server_hello") == 0) {
            ParseServerHello(root);
        } else if (msg_type && strcmp(msg_type, "session") == 0) {
            // Handle session-related messages
            // TODO: Implement session management logic
        } else if (msg_type && strcmp(msg_type, "audio_control") == 0) {
            // Handle audio control commands
            // TODO: Implement audio channel control logic
        }

        cJSON_Delete(root);
    });

    // Connect to MQTT broker
    bool success = mqtt_->Connect(config);

    if (!success) {
        ESP_LOGE(TAG, "Failed to connect to MQTT broker");
        if (report_error) {
            // TODO: Implement error reporting mechanism
        }
        return false;
    }

    ESP_LOGI(TAG, "MQTT client started successfully");
    return true;
}

