bool MqttProtocol::SendText(const std::string& text) {
    // Check if MQTT client exists and is valid
    if (!mqtt_) {
        ESP_LOGE(TAG, "MQTT client not initialized");
        Application::GetInstance().SetServerErrorState(true);
        return false;
    }

    // Check if we have a publish topic
    if (publish_topic_.empty()) {
        ESP_LOGE(TAG, "Publish topic not configured");
        Application::GetInstance().SetServerErrorState(true);
        return false;
    }

    // Attempt to publish the message
    int result = mqtt_->publish(publish_topic_.c_str(), text.c_str(), text.length(), 1, false);

    if (result != ESP_OK) {
        ESP_LOGE(TAG, "Failed to publish message to topic '%s', error: %d", publish_topic_.c_str(), result);
        Application::GetInstance().SetServerErrorState(true);
        return false;
    }

    ESP_LOGI(TAG, "Successfully published text message to topic '%s'", publish_topic_.c_str());
    return true;
}

