bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Lock the channel mutex for thread-safe access
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Check if UDP is available
    if (!udp_ || !udp_->IsConnected()) {
        ESP_LOGE(TAG, "UDP not connected, cannot send audio");
        return false;
    }

    // Validate packet
    if (!packet) {
        ESP_LOGE(TAG, "Invalid audio packet");
        return false;
    }

    // Prepare binary protocol header
    BinaryProtocol2 header;
    header.version = 2;
    header.type = 0; // OPUS audio type
    header.reserved = 0;
    header.timestamp = packet->timestamp;
    header.payload_size = packet->payload.size();

    // Create nonce for AES-CTR encryption
    // Nonce includes packet size, timestamp, and sequence number
    std::string nonce = aes_nonce_;
    nonce.resize(16); // Ensure proper size

    // Update nonce with packet information
    uint32_t* nonce_ptr = reinterpret_cast<uint32_t*>(nonce.data());
    nonce_ptr[0] = htonl(packet->payload.size());
    nonce_ptr[1] = htonl(packet->timestamp);
    nonce_ptr[2] = htonl(local_sequence_);

    // Increment sequence number
    local_sequence_++;

    // Encrypt the payload using AES-CTR mode
    std::vector<uint8_t> encrypted_payload(packet->payload.size());
    unsigned char counter[16] = {0};
    memcpy(counter, nonce.data(), 16);

    // Initialize AES context for CTR mode
    mbedtls_aes_setkey_enc(&aes_ctx_, reinterpret_cast<const unsigned char*>(aes_nonce_.data()), 128);

    // Perform AES-CTR encryption
    int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, 
                                   packet->payload.size(),
                                   counter,
                                   nonce.data(),
                                   packet->payload.data(),
                                   encrypted_payload.data());

    if (ret != 0) {
        ESP_LOGE(TAG, "AES-CTR encryption failed: %d", ret);
        return false;
    }

    // Combine header and encrypted payload
    std::vector<uint8_t> packet_data(sizeof(BinaryProtocol2) + encrypted_payload.size());
    memcpy(packet_data.data(), &header, sizeof(BinaryProtocol2));
    memcpy(packet_data.data() + sizeof(BinaryProtocol2), encrypted_payload.data(), encrypted_payload.size());

    // Send over UDP
    int sent_bytes = udp_->SendTo(packet_data.data(), packet_data.size(), 
                                  udp_server_.c_str(), udp_port_);

    if (sent_bytes <= 0) {
        ESP_LOGE(TAG, "Failed to send audio packet over UDP");
        return false;
    }

    return true;
}

