void MqttProtocol::CloseAudioChannel() {
    std::lock_guard<std::mutex> lock(channel_mutex_);

    ESP_LOGD(TAG, "Closing audio channel");

    // Reset UDP connection if it exists
    if (udp_ != nullptr) {
        udp_->Reset();
        udp_ = nullptr;
    }

    // Send goodbye message to server
    cJSON* root = cJSON_CreateObject();
    if (root != nullptr) {
        cJSON_AddStringToObject(root, "type", "goodbye");
        cJSON_AddNumberToObject(root, "sequence", local_sequence_);

        char* json_string = cJSON_PrintUnformatted(root);
        if (json_string != nullptr) {
            SendText(json_string);
            free(json_string);
        }
        cJSON_Delete(root);
    }

    // Trigger callback notification to application
    if (alive_.load()) {
        Application::GetInstance().OnAudioChannelClosed();
    }

    ESP_LOGD(TAG, "Audio channel closed");
}

