bool MqttProtocol::OpenAudioChannel() {
    ESP_LOGI(TAG, "Opening audio channel");

    // Initialize AES context
    mbedtls_aes_init(&aes_ctx_);

    // Start MQTT client
    if (!StartMqttClient(true)) {
        ESP_LOGE(TAG, "Failed to start MQTT client");
        return false;
    }

    // Send hello message
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message)) {
        ESP_LOGE(TAG, "Failed to send hello message");
        return false;
    }

    // Wait for server hello response with timeout
    TickType_t wait_time = pdMS_TO_TICKS(5000); // 5 seconds timeout
    EventBits_t bits = xEventGroupWaitBits(event_group_handle_, 
                                          MQTT_PROTOCOL_SERVER_HELLO_EVENT,
                                          pdTRUE, pdFALSE, wait_time);

    if (!(bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT)) {
        ESP_LOGE(TAG, "Timeout waiting for server hello response");
        return false;
    }

    // Setup UDP connection for audio packets
    udp_ = std::make_unique<Udp>();
    if (!udp_->Connect(udp_server_.c_str(), udp_port_)) {
        ESP_LOGE(TAG, "Failed to connect UDP socket");
        return false;
    }

    // Set up AES decryption context with nonce
    if (mbedtls_aes_setkey_dec(&aes_ctx_, 
                              reinterpret_cast<const unsigned char*>(aes_nonce_.data()),
                              aes_nonce_.size() * 8) != 0) {
        ESP_LOGE(TAG, "Failed to set AES decryption key");
        return false;
    }

    // Initialize sequence numbers
    local_sequence_ = 0;
    remote_sequence_ = 0;

    // Start listening for audio packets in a separate task or callback
    // This would typically involve setting up a UDP receive callback
    // For now, we'll assume the framework handles this

    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}

