std::string MqttProtocol::GetHelloMessage() {
    cJSON *root = cJSON_CreateObject();
    if (!root) {
        ESP_LOGE(TAG, "Failed to create JSON root object");
        return "";
    }

    // Add device capabilities
    cJSON *capabilities = cJSON_CreateObject();
    if (capabilities) {
        cJSON_AddBoolToObject(capabilities, "aec", true);
        cJSON_AddBoolToObject(capabilities, "mcp", true);
        cJSON_AddItemToObject(root, "capabilities", capabilities);
    }

    // Add audio parameters
    cJSON *audio = cJSON_CreateObject();
    if (audio) {
        cJSON_AddStringToObject(audio, "format", "pcm");
        cJSON_AddNumberToObject(audio, "sampleRate", 16000);
        cJSON_AddNumberToObject(audio, "frameDuration", 20);
        cJSON_AddItemToObject(root, "audio", audio);
    }

    // Add device info (optional but common in hello messages)
    cJSON *device = cJSON_CreateObject();
    if (device) {
        cJSON_AddStringToObject(device, "type", "esp32");
        cJSON_AddItemToObject(root, "device", device);
    }

    // Convert to string
    char *json_string = cJSON_Print(root);
    if (!json_string) {
        ESP_LOGE(TAG, "Failed to print JSON");
        cJSON_Delete(root);
        return "";
    }

    std::string result(json_string);

    // Clean up
    free(json_string);
    cJSON_Delete(root);

    return result;
}

