void MqttProtocol::ParseServerHello(const cJSON* root) {
    // Extract UDP server address
    const cJSON* server_obj = cJSON_GetObjectItem(root, "server");
    if (server_obj && cJSON_IsString(server_obj)) {
        udp_server_ = cJSON_GetStringValue(server_obj);
    }

    // Extract UDP port
    const cJSON* port_obj = cJSON_GetObjectItem(root, "port");
    if (port_obj && cJSON_IsNumber(port_obj)) {
        udp_port_ = cJSON_GetNumberValue(port_obj);
    }

    // Extract encryption key
    const cJSON* key_obj = cJSON_GetObjectItem(root, "key");
    if (key_obj && cJSON_IsString(key_obj)) {
        std::string key = cJSON_GetStringValue(key_obj);
        // Convert hex string to binary data for AES key
        std::string decoded_key = DecodeHexString(key);
        if (decoded_key.length() == 16) {  // AES-128 key size
            mbedtls_aes_init(&aes_ctx_);
            mbedtls_aes_setkey_enc(&aes_ctx_, (const unsigned char*)decoded_key.data(), 128);
        }
    }

    // Extract nonce
    const cJSON* nonce_obj = cJSON_GetObjectItem(root, "nonce");
    if (nonce_obj && cJSON_IsString(nonce_obj)) {
        aes_nonce_ = cJSON_GetStringValue(nonce_obj);
    }

    // Extract audio parameters
    const cJSON* audio_obj = cJSON_GetObjectItem(root, "audio");
    if (audio_obj) {
        // Extract sample rate
        const cJSON* sample_rate_obj = cJSON_GetObjectItem(audio_obj, "sample_rate");
        if (sample_rate_obj && cJSON_IsNumber(sample_rate_obj)) {
            // Store sample rate if needed for future use
            int sample_rate = cJSON_GetNumberValue(sample_rate_obj);
            // Assuming we have a way to store this, but not directly used in current implementation
        }

        // Extract frame duration
        const cJSON* frame_duration_obj = cJSON_GetObjectItem(audio_obj, "frame_duration");
        if (frame_duration_obj && cJSON_IsNumber(frame_duration_obj)) {
            // Store frame duration if needed for future use
            int frame_duration = cJSON_GetNumberValue(frame_duration_obj);
            // Assuming we have a way to store this, but not directly used in current implementation
        }
    }

    // Signal that server hello has been processed
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

