std::string MqttProtocol::DecodeHexString(const std::string& hex_string) {
    std::string result;

    // Process the hex string two characters at a time
    for (size_t i = 0; i < hex_string.length(); i += 2) {
        // Check if we have at least 2 characters left
        if (i + 1 >= hex_string.length()) {
            // Odd number of characters, skip the last one or handle as needed
            // For now, we'll just skip incomplete pairs
            break;
        }

        // Extract two characters
        char hex_char1 = hex_string[i];
        char hex_char2 = hex_string[i + 1];

        // Convert hex characters to decimal values
        int val1, val2;

        // Handle first character
        if (hex_char1 >= '0' && hex_char1 <= '9') {
            val1 = hex_char1 - '0';
        } else if (hex_char1 >= 'A' && hex_char1 <= 'F') {
            val1 = hex_char1 - 'A' + 10;
        } else if (hex_char1 >= 'a' && hex_char1 <= 'f') {
            val1 = hex_char1 - 'a' + 10;
        } else {
            // Invalid hex character, skip this pair
            continue;
        }

        // Handle second character
        if (hex_char2 >= '0' && hex_char2 <= '9') {
            val2 = hex_char2 - '0';
        } else if (hex_char2 >= 'A' && hex_char2 <= 'F') {
            val2 = hex_char2 - 'A' + 10;
        } else if (hex_char2 >= 'a' && hex_char2 <= 'f') {
            val2 = hex_char2 - 'a' + 10;
        } else {
            // Invalid hex character, skip this pair
            continue;
        }

        // Combine the two hex values into a single byte
        char byte_val = static_cast<char>((val1 << 4) | val2);
        result.push_back(byte_val);
    }

    return result;
}

