void Protocol::SendAbortSpeaking(AbortReason reason)
{
    cJSON *root = cJSON_CreateObject();
    if (!root) {
        ESP_LOGE(TAG, "Failed to create JSON object for abort speaking message");
        return;
    }

    // Add session ID
    if (session_id_.empty()) {
        ESP_LOGW(TAG, "Session ID is empty when sending abort speaking message");
    }
    cJSON_AddStringToObject(root, "sessionId", session_id_.c_str());

    // Add abort reason
    switch (reason) {
        case kAbortReasonNone:
            cJSON_AddStringToObject(root, "reason", "none");
            break;
        case kAbortReasonWakeWordDetected:
            cJSON_AddStringToObject(root, "reason", "wake_word_detected");
            break;
        default:
            cJSON_AddStringToObject(root, "reason", "unknown");
            break;
    }

    // Convert to string and send
    char *json_string = cJSON_Print(root);
    if (json_string) {
        SendText(json_string);
        cJSON_free(json_string);
    } else {
        ESP_LOGE(TAG, "Failed to print JSON for abort speaking message");
    }

    cJSON_Delete(root);
}

