void Protocol::SendWakeWordDetected(const std::string& wake_word)
{
    cJSON* root = cJSON_CreateObject();
    if (!root) {
        ESP_LOGE(TAG, "Failed to create JSON object for wake word detection");
        return;
    }

    // Add session ID
    if (!cJSON_AddStringToObject(root, "session_id", session_id_.c_str())) {
        ESP_LOGE(TAG, "Failed to add session_id to JSON");
        cJSON_Delete(root);
        return;
    }

    // Add interaction type
    if (!cJSON_AddStringToObject(root, "interaction_type", "wake_word_detected")) {
        ESP_LOGE(TAG, "Failed to add interaction_type to JSON");
        cJSON_Delete(root);
        return;
    }

    // Add state
    if (!cJSON_AddStringToObject(root, "state", "detected")) {
        ESP_LOGE(TAG, "Failed to add state to JSON");
        cJSON_Delete(root);
        return;
    }

    // Add wake word
    if (!cJSON_AddStringToObject(root, "wake_word", wake_word.c_str())) {
        ESP_LOGE(TAG, "Failed to add wake_word to JSON");
        cJSON_Delete(root);
        return;
    }

    // Convert to string and send
    char* json_string = cJSON_Print(root);
    if (json_string) {
        SendText(json_string);
        free(json_string);
    } else {
        ESP_LOGE(TAG, "Failed to print JSON");
    }

    cJSON_Delete(root);
}

