void Protocol::SendStartListening(ListeningMode mode) {
    cJSON *json = cJSON_CreateObject();
    cJSON_AddStringToObject(json, "type", "listen");
    cJSON_AddStringToObject(json, "state", "start");
    cJSON_AddStringToObject(json, "sessionId", session_id_.c_str());

    // Map ListeningMode enum to string representation
    const char* mode_str;
    switch (mode) {
        case kListeningModeAutoStop:
            mode_str = "auto";
            break;
        case kListeningModeManualStop:
            mode_str = "manual";
            break;
        case kListeningModeRealtime:
            mode_str = "realtime";
            break;
        default:
            mode_str = "unknown";
            break;
    }
    cJSON_AddStringToObject(json, "mode", mode_str);

    char* json_str = cJSON_PrintUnformatted(json);
    std::string message(json_str);
    cJSON_free(json_str);
    cJSON_Delete(json);

    SendText(message);
}

