void Protocol::SendStopListening()
{
    cJSON *root = cJSON_CreateObject();
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to create JSON object for stop listening message");
        return;
    }

    // Set the message type to "listen"
    cJSON_AddStringToObject(root, "type", "listen");

    // Set the state to "stop"
    cJSON_AddStringToObject(root, "state", "stop");

    // Include the current session ID
    cJSON_AddStringToObject(root, "session_id", session_id_.c_str());

    // Convert JSON to string and send
    char *json_string = cJSON_PrintUnformatted(root);
    if (json_string != nullptr) {
        SendMcpMessage(json_string);
        free(json_string);
    } else {
        ESP_LOGE(TAG, "Failed to print JSON for stop listening message");
    }

    // Clean up
    cJSON_Delete(root);
}

