bool WebsocketProtocol::Start()
{
    // Initialize WebSocket connection
    websocket_ = std::make_unique<WebSocket>();

    // Connect to the WebSocket server
    // Note: The actual connection parameters would typically come from settings
    // For now, assuming we have a default server address
    const char* server_url = "ws://localhost:8080/ws"; // This should be configurable

    // Attempt to connect to the WebSocket server
    if (!websocket_->Connect(server_url)) {
        ESP_LOGE(TAG, "Failed to connect to WebSocket server");
        return false;
    }

    // Send the hello message to establish connection
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message)) {
        ESP_LOGE(TAG, "Failed to send hello message");
        websocket_.reset(); // Clean up connection
        return false;
    }

    ESP_LOGI(TAG, "WebSocket connection started successfully");
    return true;
}

