bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Check if WebSocket connection exists and is valid
    if (!websocket_ || !websocket_->IsConnected()) {
        ESP_LOGW(TAG, "WebSocket not connected, cannot send audio");
        return false;
    }

    // Validate packet
    if (!packet) {
        ESP_LOGE(TAG, "Invalid audio packet");
        return false;
    }

    // Prepare the data to send
    std::vector<uint8_t> buffer;

    switch (version_) {
        case 2: {
            // Version 2 binary protocol
            BinaryProtocol2 header;
            header.version = htons(2);
            header.type = htons(0); // OPUS audio type
            header.reserved = 0;
            header.timestamp = htonl(packet->timestamp);
            header.payload_size = htonl(packet->payload.size());

            // Reserve space for header + payload
            buffer.resize(sizeof(BinaryProtocol2) + packet->payload.size());

            // Copy header
            memcpy(buffer.data(), &header, sizeof(BinaryProtocol2));

            // Copy payload
            if (!packet->payload.empty()) {
                memcpy(buffer.data() + sizeof(BinaryProtocol2), packet->payload.data(), packet->payload.size());
            }
            break;
        }

        case 3: {
            // Version 3 binary protocol
            BinaryProtocol3 header;
            header.type = 0; // OPUS audio type
            header.reserved = 0;
            header.payload_size = htons(packet->payload.size());

            // Reserve space for header + payload
            buffer.resize(sizeof(BinaryProtocol3) + packet->payload.size());

            // Copy header
            memcpy(buffer.data(), &header, sizeof(BinaryProtocol3));

            // Copy payload
            if (!packet->payload.empty()) {
                memcpy(buffer.data() + sizeof(BinaryProtocol3), packet->payload.data(), packet->payload.size());
            }
            break;
        }

        default: {
            // Raw payload format for other versions
            buffer = packet->payload;
            break;
        }
    }

    // Send the audio data through WebSocket
    bool result = websocket_->SendBinary(buffer.data(), buffer.size());

    if (!result) {
        ESP_LOGE(TAG, "Failed to send audio data over WebSocket");
        return false;
    }

    return true;
}

