bool WebsocketProtocol::OpenAudioChannel() {
    // Check if WebSocket is already open
    if (websocket_ != nullptr) {
        ESP_LOGW(TAG, "WebSocket already opened");
        return true;
    }

    // Create WebSocket instance
    websocket_ = std::make_unique<WebSocket>();
    if (!websocket_) {
        ESP_LOGE(TAG, "Failed to create WebSocket instance");
        return false;
    }

    // Configure WebSocket settings
    WebSocketConfig config;
    config.uri = GetServerUri(); // Assuming this method exists
    config.headers["Authorization"] = GetAuthHeader(); // Authentication header
    config.headers["X-Protocol-Version"] = std::to_string(version_);
    config.headers["X-Device-ID"] = GetDeviceId(); // Assuming this method exists

    // Set up binary data handler for different protocol versions
    if (version_ == 2 || version_ == 3) {
        config.binary_handler = [this](const uint8_t* data, size_t length) {
            // Handle binary audio packets based on protocol version
            if (version_ == 2) {
                // Process v2 protocol format
                if (length >= sizeof(uint32_t)) {
                    uint32_t payload_size = ntohl(*reinterpret_cast<const uint32_t*>(data));
                    if (payload_size + sizeof(uint32_t) <= length) {
                        // Extract payload with proper byte order conversion
                        const uint8_t* payload = data + sizeof(uint32_t);
                        // Process audio packet
                        if (on_incoming_audio_ != nullptr) {
                            // Create audio packet with extracted data
                            auto packet = std::make_unique<AudioStreamPacket>();
                            packet->data = std::vector<uint8_t>(payload, payload + payload_size);
                            packet->timestamp = esp_timer_get_time();
                            on_incoming_audio_(std::move(packet));
                        }
                    }
                }
            } else if (version_ == 3) {
                // Process v3 protocol format
                if (length >= sizeof(uint32_t) * 2) {
                    uint32_t header = ntohl(*reinterpret_cast<const uint32_t*>(data));
                    uint32_t payload_size = ntohl(*reinterpret_cast<const uint32_t*>(data + sizeof(uint32_t)));

                    if (payload_size + sizeof(uint32_t) * 2 <= length) {
                        // Extract payload with proper byte order conversion
                        const uint8_t* payload = data + sizeof(uint32_t) * 2;
                        // Process audio packet
                        if (on_incoming_audio_ != nullptr) {
                            // Create audio packet with extracted data
                            auto packet = std::make_unique<AudioStreamPacket>();
                            packet->data = std::vector<uint8_t>(payload, payload + payload_size);
                            packet->timestamp = esp_timer_get_time();
                            on_incoming_audio_(std::move(packet));
                        }
                    }
                }
            }
        };
    } else {
        ESP_LOGW(TAG, "Unsupported protocol version: %d", version_);
        return false;
    }

    // Connect to WebSocket
    if (!websocket_->Connect(config)) {
        ESP_LOGE(TAG, "Failed to connect WebSocket");
        websocket_.reset();
        return false;
    }

    // Wait for connection establishment
    EventBits_t bits = xEventGroupWaitBits(event_group_handle_, 
                                          WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT,
                                          pdTRUE, pdFALSE, pdMS_TO_TICKS(5000));
    if (!(bits & WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT)) {
        ESP_LOGW(TAG, "Timeout waiting for server hello");
        websocket_.reset();
        return false;
    }

    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}

