std::string WebsocketProtocol::GetHelloMessage() {
    cJSON *root = cJSON_CreateObject();

    // Add protocol version
    cJSON_AddNumberToObject(root, "version", version_);

    // Add supported features
    cJSON *features = cJSON_CreateObject();
    cJSON_AddBoolToObject(features, "aec", true);  // AEC support
    cJSON_AddBoolToObject(features, "mcp", true);  // MCP support
    cJSON_AddItemToObject(root, "features", features);

    // Add transport method
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Add audio parameters
    cJSON *audio = cJSON_CreateObject();
    cJSON_AddStringToObject(audio, "format", "pcm");  // Assuming PCM format
    cJSON_AddNumberToObject(audio, "sample_rate", 16000);  // Typical sample rate
    cJSON_AddNumberToObject(audio, "channels", 1);  // Mono audio
    cJSON_AddNumberToObject(audio, "frame_duration", 20);  // 20ms frame duration
    cJSON_AddItemToObject(root, "audio", audio);

    // Convert to string
    char *json_string = cJSON_Print(root);
    std::string result(json_string);

    // Clean up
    cJSON_Delete(root);
    free(json_string);

    return result;
