void WebsocketProtocol::ParseServerHello(const cJSON* root)
{
    // Extract server frame duration from JSON
    cJSON* frame_duration = cJSON_GetObjectItem(root, "frame_duration");
    if (frame_duration != nullptr && cJSON_IsNumber(frame_duration))
    {
        server_frame_duration_ = frame_duration->valueint;
    }

    // Extract server sample rate from JSON
    cJSON* sample_rate = cJSON_GetObjectItem(root, "sample_rate");
    if (sample_rate != nullptr && cJSON_IsNumber(sample_rate))
    {
        server_sample_rate_ = sample_rate->valueint;
    }

    // Extract transport type from JSON
    cJSON* transport_type = cJSON_GetObjectItem(root, "transport_type");
    if (transport_type != nullptr && cJSON_IsString(transport_type))
    {
        // Validate transport type (assuming we only accept certain types)
        const char* transport_str = transport_type->valuestring;
        if (strcmp(transport_str, "websocket") == 0)
        {
            // Transport type is valid, set the event flag
            xEventGroupSetBits(event_group_handle_, WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT);
        }
        else
        {
            ESP_LOGE(TAG, "Invalid transport type: %s", transport_str);
        }
    }
    else
    {
        ESP_LOGE(TAG, "Missing or invalid transport_type in server hello");
    }
}
